window._students  = [];
window._groceries = [];
window._teachers  = [];
window._customRewards = [];
window._currentTeacher = null;

let currentAction = null, currentStudentId = null, bulkAction = null;
let currentDeleteTeacherId = null, currentEditGroupKey = null;
let selectedPrintItems = new Set();
let searchFilter = '', classFilter = '';
let selectedTeacherColor = '#1D9E75';

function fbRef(path) { return window._ref(window._db, path); }
function ready()     { return !!(window._fbReady && window._db && window._ref); }
function openKlasseportal() {
  try {
    var t = window._currentTeacher;
    if (t) localStorage.setItem('myntland-portal-link-v1', JSON.stringify({
      workspaceId: t.workspaceId || 'main', trinn: '14',
      className: t.class || '', teacherName: t.name || '', role: t.role || 'teacher'
    }));
  } catch (e) {}
  window.open('klasseportal.html', '_blank');
}

// ══════════════════════════════════════════════════════════
// LOGIN / TEACHER PROFILES
// ══════════════════════════════════════════════════════════
let loginPin = '', loginTarget = null;

// Load teacher profiles for login screen
function loadProfiles() {
  window._onValue(fbRef('teachers'), snap => {
    window._teachers = snap.val()
      ? Object.entries(snap.val()).map(([k,v]) => ({...v, fbKey:k}))
      : [];
    renderLoginProfiles();
    if (document.getElementById('page-laerere').classList.contains('active')) renderTeacherList();
    // Seed default admin if no teachers exist
    if (!window._teachers.length) seedDefaultAdmin();
  });
}

function seedDefaultAdmin() {
  window._set(window._push(fbRef('teachers')), {
    name: 'Administrator', pin: '1379', role: 'admin', color: '#085041', class: ''
  });
}

function renderLoginProfiles() {
  const el = document.getElementById('profile-list');
  if (!window._teachers.length) {
    el.innerHTML = '<div style="text-align:center;color:var(--muted);padding:1rem;font-size:.85rem;">Ingen profiler ennå – første gangs PIN er 1379</div>';
    return;
  }
  el.innerHTML = window._teachers.map(t => `
    <button class="profile-btn" onclick="selectProfile('${t.fbKey}')">
      <div class="profile-avatar" style="background:${t.color}22;color:${t.color};">${t.name[0].toUpperCase()}</div>
      <div>
        <div class="profile-name">${t.name}</div>
        <div class="profile-role">${t.role === 'admin' ? '⚙️ Administrator' : `👩‍🏫 Lærer${t.class ? ' – klasse ' + t.class : ''}`}</div>
      </div>
    </button>`).join('');
}

function selectProfile(fbKey) {
  loginTarget = window._teachers.find(t => t.fbKey === fbKey);
  loginPin = '';
  document.getElementById('pin-for-name').textContent = 'PIN for ' + loginTarget.name;
  document.getElementById('login-error').textContent = '';
  updateLoginDots();
  document.getElementById('profile-list').style.display = 'none';
  document.getElementById('pin-section').style.display = 'block';
}

function backToProfiles() {
  loginPin = ''; loginTarget = null;
  document.getElementById('pin-section').style.display = 'none';
  document.getElementById('profile-list').style.display = 'flex';
  document.getElementById('profile-list').style.flexDirection = 'column';
}

function pinKey(val) {
  if (val === 'DEL') loginPin = loginPin.slice(0,-1);
  else if (loginPin.length < 4) loginPin += val;
  updateLoginDots();
  document.getElementById('login-error').textContent = '';
  if (loginPin.length === 4) setTimeout(tryTeacherLogin, 150);
}

function updateLoginDots() {
  ['pc-0','pc-1','pc-2','pc-3'].forEach((id,i) => {
    const el = document.getElementById(id);
    el.textContent = i < loginPin.length ? '●' : '·';
    el.classList.toggle('filled', i < loginPin.length);
  });
}

function tryTeacherLogin() {
  if (loginPin === String(loginTarget.pin)) {
    window._currentTeacher = loginTarget;
    document.getElementById('login-screen').style.display = 'none';
    document.getElementById('app').style.display = 'block';
    // Set header
    document.getElementById('header-name').textContent = loginTarget.name;
    const av = document.getElementById('header-avatar');
    av.textContent = loginTarget.name[0].toUpperCase();
    av.style.background = loginTarget.color + '33';
    av.style.color = loginTarget.color;
    // Show admin nav if admin
    if (loginTarget.role === 'admin') {
      document.getElementById('nav-laerere').style.display = '';
    }
    // Update subtitle
    const sub = document.getElementById('elever-subtitle');
    sub.textContent = loginTarget.class
      ? `Viser klasse ${loginTarget.class}`
      : 'Alle klasser';
    // Populate class filter with teacher's class pre-selected
    if (loginTarget.class && loginTarget.role !== 'admin') {
      classFilter = loginTarget.class;
    }
    applyTeacherClassLock();
    window._startListeners();
    showPage('elever');
  } else {
    document.getElementById('login-error').textContent = '❌ Feil PIN – prøv igjen';
    loginPin = ''; updateLoginDots();
  }
}

// Klasse-lås: vanlig lærer skal kun se sin egen klasse i opprett-dropdowns.
function applyTeacherClassLock() {
  const t = window._currentTeacher;
  if (!t || t.role === 'admin' || !t.class) return;
  const cls = t.class;
  ['new-class', 'bulk-class-select'].forEach(function(id) {
    const sel = document.getElementById(id);
    if (sel) {
      sel.innerHTML = '<option value="' + cls + '">' + cls + '</option>';
      sel.value = cls;
      sel.disabled = true;
      sel.style.background = 'var(--bg)';
      sel.style.color = 'var(--muted)';
      sel.title = 'Du kan kun opprette elever i din egen klasse (' + cls + ')';
    }
  });
}

function doLogout() {
  window._currentTeacher = null;
  searchFilter = ''; classFilter = '';
  document.getElementById('app').style.display = 'none';
  document.getElementById('login-screen').style.display = 'flex';
  document.getElementById('pin-section').style.display = 'none';
  document.getElementById('profile-list').style.display = 'flex';
  document.getElementById('profile-list').style.flexDirection = 'column';
  document.getElementById('nav-laerere').style.display = 'none';
  loginPin = ''; loginTarget = null;
}

// ── Teacher CRUD (admin only) ──────────────────────────────────────────────
function selectTeacherColor(el) {
  document.querySelectorAll('#teacher-color-picker .color-swatch').forEach(s => s.classList.remove('selected'));
  el.classList.add('selected');
  selectedTeacherColor = el.dataset.color;
}

async function createTeacher() {
  const name  = document.getElementById('new-teacher-name').value.trim();
  const pin   = document.getElementById('new-teacher-pin').value.trim();
  const cls   = document.getElementById('new-teacher-class').value.trim();
  const role  = document.getElementById('new-teacher-role').value;
  const alertEl = document.getElementById('teacher-create-alert');
  if (!name || !pin || pin.length !== 4 || !/^\d{4}$/.test(pin)) {
    alertEl.innerHTML = '<div class="alert alert-error">⚠️ Fyll inn navn og en 4-sifret PIN.</div>'; return;
  }
  await window._set(window._push(fbRef('teachers')), { name, pin, role, class: cls, color: selectedTeacherColor });
  document.getElementById('new-teacher-name').value = '';
  document.getElementById('new-teacher-pin').value  = '';
  document.getElementById('new-teacher-class').value = '';
  alertEl.innerHTML = `<div class="alert alert-success">✅ ${name} er opprettet!</div>`;
  setTimeout(() => alertEl.innerHTML = '', 3000);
}

function renderTeacherList() {
  const el = document.getElementById('teacher-list');
  if (!el) return;
  el.innerHTML = window._teachers.map(t => `
    <div class="teacher-card">
      <div class="teacher-card-avatar" style="background:${t.color}22;color:${t.color};">${t.name[0].toUpperCase()}</div>
      <div class="teacher-card-info">
        <div class="teacher-card-name">${t.name}</div>
        <div class="teacher-card-meta">${t.role === 'admin' ? '⚙️ Admin' : '👩‍🏫 Lærer'}${t.class ? ' · klasse ' + t.class : ' · alle klasser'} · PIN: ${t.pin}</div>
      </div>
      ${t.fbKey !== window._currentTeacher?.fbKey ? `<button class="btn btn-coral btn-sm" onclick="openDeleteTeacherModal('${t.fbKey}','${t.name}')">🗑️</button>` : '<span style="font-size:.75rem;color:var(--muted);">(deg)</span>'}
    </div>`).join('') || '<p style="color:var(--muted);font-size:.85rem;">Ingen lærere ennå.</p>';
}

function openDeleteTeacherModal(fbKey, name) {
  currentDeleteTeacherId = fbKey;
  document.getElementById('modal-delete-teacher-text').textContent = `Slett lærerprofilen til ${name}?`;
  document.getElementById('modal-delete-teacher').classList.add('open');
}
async function confirmDeleteTeacher() {
  await window._remove(fbRef('teachers/' + currentDeleteTeacherId));
  closeModal('modal-delete-teacher');
}

// ══════════════════════════════════════════════════════════
// NAVIGATION
// ══════════════════════════════════════════════════════════
function showPage(page) {
  // Bakoverkompatibilitet: gamle sidenavn (sparemaal, qrkoder, hendelser, merker)
  // er nå tabs på Belønninger-siden. Rut til riktig fane.
  const tabMap = {
    sparemaal: 'sparemaal',
    qrkoder:   'qrkoder',
    hendelser: 'hendelser',
    merker:    'merker',
    myntjakten:'myntjakten'
  };
  if (tabMap[page]) {
    showPage('belonninger');
    setTimeout(() => {
      const btn = document.querySelector('#page-belonninger .tabs button[onclick*="' + tabMap[page] + '"]');
      if (btn) showBelonningTab(tabMap[page], btn);
    }, 0);
    return;
  }

  document.querySelectorAll('.page').forEach(p => p.classList.remove('active'));
  document.querySelectorAll('header nav button').forEach(b => b.classList.remove('active'));
  document.getElementById('page-' + page).classList.add('active');
  document.getElementById('nav-' + page).classList.add('active');
  if (page === 'laerere') renderTeacherList();
  if (page === 'saldo') renderSaldoTable();
  if (page === 'butikk') {
    if (typeof renderGroceryList === 'function') renderGroceryList();
    if (typeof renderHandlelisteSelect === 'function') renderHandlelisteSelect();
    if (typeof syncRealPaymentsToggle === 'function') syncRealPaymentsToggle();
  }
  if (page === 'belonninger') {
    if (typeof renderClassGoalsPage   === 'function') renderClassGoalsPage();
    if (typeof generateRewardQRCodes  === 'function') { generateRewardQRCodes(); renderCustomRewards(); }
    if (typeof renderHendelser        === 'function') renderHendelser();
    if (typeof renderMerkerPage       === 'function') renderMerkerPage();
    if (typeof syncMyntjakten14Form   === 'function') syncMyntjakten14Form();
  }
  if (page === 'elever' && typeof syncLoginModeToggle === 'function') syncLoginModeToggle();
  // Close mobile nav after selection
  const nav = document.querySelector('header nav');
  const btn = document.getElementById('hamburger-btn');
  if (nav && btn) { nav.classList.remove('open'); btn.classList.remove('open'); }
}

// Bytt fane på Belønninger-siden
function showBelonningTab(tab, btnEl) {
  ['sparemaal','qrkoder','hendelser','merker','myntjakten'].forEach(t => {
    const el = document.getElementById('bel-tab-' + t);
    if (el) el.style.display = (t === tab) ? 'block' : 'none';
  });
  if (btnEl && btnEl.closest) {
    btnEl.closest('.tabs').querySelectorAll('.tab').forEach(b => b.classList.remove('active'));
    btnEl.classList.add('active');
  }
  if (tab === 'sparemaal'  && typeof renderClassGoalsPage  === 'function') renderClassGoalsPage();
  if (tab === 'qrkoder'    && typeof generateRewardQRCodes === 'function') { generateRewardQRCodes(); renderCustomRewards(); }
  if (tab === 'hendelser'  && typeof renderHendelser       === 'function') renderHendelser();
  if (tab === 'merker'     && typeof renderMerkerPage      === 'function') renderMerkerPage();
  if (tab === 'myntjakten' && typeof syncMyntjakten14Form  === 'function') syncMyntjakten14Form();
}

function toggleMobileNav() {
  const nav = document.querySelector('header nav');
  const btn = document.getElementById('hamburger-btn');
  nav.classList.toggle('open');
  btn.classList.toggle('open');
}

function showElevTab(tab, btn) {
  ['manuell','klasse','bankkort','klasser'].forEach(t => {
    const el = document.getElementById('elev-tab-' + t);
    if (el) el.style.display = t === tab ? 'block' : 'none';
  });
  btn.closest('.tabs').querySelectorAll('.tab').forEach(b => b.classList.remove('active'));
  btn.classList.add('active');
  if (tab === 'klasser') renderClassManager();
  if (tab === 'klasse') populatePrintClassSelect();
  if (typeof applyTeacherClassLock === 'function') applyTeacherClassLock();
}

function getClassNames() {
  return [...new Set(window._students.map(s => s.class))].filter(Boolean).sort();
}

function renderClassManager() {
  // Populate the rename dropdown with current classes
  const classes = getClassNames();
  const rf = document.getElementById('rename-class-from');
  if (rf) {
    const cur = rf.value;
    rf.innerHTML = '<option value="">– Velg klasse –</option>' +
      classes.map(c => `<option value="${c}"${c===cur?' selected':''}>${c}</option>`).join('');
  }
  // Show class list with student counts
  const el = document.getElementById('class-list-display');
  if (!el) return;
  if (!classes.length) {
    el.innerHTML = '<p style="font-size:.85rem;color:var(--muted);">Ingen klasser ennå – opprett elever først.</p>';
    return;
  }
  el.innerHTML = classes.map(c => {
    const count = window._students.filter(s => s.class === c).length;
    // Escape klassenavn til onclick — JSON.stringify takler navn med ' eller "
    const safeC = JSON.stringify(c).replace(/"/g, '&quot;');
    return `<div style="display:flex;align-items:center;gap:10px;padding:10px 12px;background:var(--bg);border-radius:10px;margin-bottom:8px;">
      <span style="font-size:.75rem;font-weight:800;padding:3px 10px;border-radius:20px;background:var(--purple-light);color:var(--purple);">${c}</span>
      <span style="font-size:.8rem;color:var(--muted);">${count} elev${count!==1?'er':''}</span>
      <button onclick="printExistingClassList('${c}')" style="margin-left:auto;background:var(--green-light);color:var(--green-dark);border:none;border-radius:8px;padding:5px 12px;font-family:'Nunito',sans-serif;font-size:.75rem;font-weight:800;cursor:pointer;">🖨️ Skriv ut</button>
      <button onclick="openDeleteClassModal(${safeC})" title="Slett hele klassen" style="background:none;border:1px solid var(--coral);color:var(--coral);border-radius:8px;padding:5px 10px;font-family:'Nunito',sans-serif;font-size:.75rem;font-weight:800;cursor:pointer;">🗑️ Slett</button>
    </div>`;
  }).join('') +
  `<div style="margin-top:12px;">
    <button onclick="printExistingClassList('')" style="width:100%;background:var(--amber-light);color:#854F0B;border:none;border-radius:10px;padding:10px;font-family:'Nunito',sans-serif;font-size:.85rem;font-weight:800;cursor:pointer;">🖨️ Skriv ut alle klasser samlet</button>
  </div>`;
}

async function renameClass() {
  const from    = document.getElementById('rename-class-from').value;
  const to      = document.getElementById('rename-class-to').value.trim();
  const alertEl = document.getElementById('rename-alert');
  if (!from) { alertEl.innerHTML = '<div class="alert alert-error">⚠️ Velg hvilken klasse du vil endre.</div>'; return; }
  if (!to)   { alertEl.innerHTML = '<div class="alert alert-error">⚠️ Skriv inn det nye klassenavnet.</div>'; return; }
  if (from === to) { alertEl.innerHTML = '<div class="alert alert-error">⚠️ Nytt navn er det samme som det gamle.</div>'; return; }
  const toUpdate = window._students.filter(s => s.class === from);
  if (!toUpdate.length) { alertEl.innerHTML = '<div class="alert alert-error">⚠️ Ingen elever i den valgte klassen.</div>'; return; }
  alertEl.innerHTML = '<div class="alert alert-success">⏳ Oppdaterer…</div>';
  const updates = {};
  toUpdate.forEach(s => { updates['students14/' + s.fbKey + '/class'] = to; });
  // Oppdater også eventuelle lærere som har den gamle klassen som sin egen,
  // ellers ville de mistet tilgang til elevene sine i visningen.
  const teachersToUpdate = (window._teachers || []).filter(t => t.class === from);
  teachersToUpdate.forEach(t => { updates['teachers/' + t.fbKey + '/class'] = to; });
  // Hvis det er den innloggede læreren selv, oppdater også lokal state og lås.
  if (window._currentTeacher && window._currentTeacher.class === from) {
    window._currentTeacher.class = to;
    classFilter = to;
    if (typeof applyTeacherClassLock === 'function') applyTeacherClassLock();
  }
  await window._update(fbRef('/'), updates);
  document.getElementById('rename-class-to').value = '';
  const teacherNote = teachersToUpdate.length
    ? ` Også ${teachersToUpdate.length} lærer${teachersToUpdate.length!==1?'e':''} fikk oppdatert sin klassetilhørighet.`
    : '';
  alertEl.innerHTML = `<div class="alert alert-success">✅ «${from}» → «${to}» for ${toUpdate.length} elev${toUpdate.length!==1?'er':''}.${teacherNote}</div>`;
  setTimeout(() => renderClassManager(), 600);
}

// ════════════════════════════════════════════════════════════
// SLETT HEL KLASSE
// Fjerner alle elever i en klasse + deres transaksjoner + sparekonto,
// og frigjør klasselåsen for evt. lærere låst til klassen.
// Krever at læreren skriver inn klassenavnet for å aktivere knappen.
// ════════════════════════════════════════════════════════════
let currentDeleteClassName = null;

function openDeleteClassModal(cls) {
  if (!cls) return;
  currentDeleteClassName = cls;
  const studentsInClass = (window._students || []).filter(s => s.class === cls);
  const teachersInClass = (window._teachers || []).filter(t => t.class === cls);

  const titleEl = document.getElementById('modal-delete-class-title');
  const infoEl  = document.getElementById('modal-delete-class-info');
  const matchEl = document.getElementById('modal-delete-class-match');
  const input   = document.getElementById('modal-delete-class-input');
  const btn     = document.getElementById('modal-delete-class-btn');
  if (!titleEl || !input || !btn) {
    alert('Modalen for klasse-sletting mangler i HTML-en.');
    return;
  }

  titleEl.textContent = '⚠️ Slett klasse «' + cls + '»?';
  const teacherNote = teachersInClass.length
    ? ` ${teachersInClass.length} lærer${teachersInClass.length!==1?'e er':' er'} låst til klassen og får klasselåsen fjernet (lærerprofilen beholdes).`
    : '';
  infoEl.innerHTML =
    `Du er i ferd med å <strong>slette ${studentsInClass.length} elev${studentsInClass.length!==1?'er':''}</strong> i klassen «${cls}», ` +
    `samt alle deres transaksjonslogger og sparekonti.${teacherNote}<br><br>` +
    `<strong>Dette kan ikke angres.</strong>`;
  matchEl.innerHTML = `Skriv inn klassenavnet <code style="background:var(--bg);padding:2px 6px;border-radius:4px;">${cls}</code> for å bekrefte:`;

  input.value = '';
  btn.disabled = true;
  btn.style.opacity = '0.5';
  btn.style.cursor = 'not-allowed';
  input.oninput = validateDeleteClassInput;

  document.getElementById('modal-delete-class').classList.add('open');
  setTimeout(() => input.focus(), 50);
}

function validateDeleteClassInput() {
  const input = document.getElementById('modal-delete-class-input');
  const btn   = document.getElementById('modal-delete-class-btn');
  if (!input || !btn || !currentDeleteClassName) return;
  const ok = input.value.trim() === currentDeleteClassName;
  btn.disabled = !ok;
  btn.style.opacity = ok ? '1' : '0.5';
  btn.style.cursor = ok ? 'pointer' : 'not-allowed';
}

async function confirmDeleteClass() {
  if (!currentDeleteClassName) return;
  const cls = currentDeleteClassName;
  const input = document.getElementById('modal-delete-class-input');
  if (!input || input.value.trim() !== cls) return; // ekstra vakt

  const btn    = document.getElementById('modal-delete-class-btn');
  const cancel = document.querySelector('#modal-delete-class .btn-ghost');
  const origText = btn ? btn.textContent : '';
  if (btn) { btn.disabled = true; btn.textContent = '⏳ Sletter…'; btn.style.cursor = 'wait'; }
  if (cancel) cancel.disabled = true;

  try {
    const studentsInClass = (window._students || []).filter(s => s.class === cls);
    const teachersInClass = (window._teachers || []).filter(t => t.class === cls);

    const updates = {};
    studentsInClass.forEach(s => {
      updates['students14/' + s.fbKey] = null;
      updates['transactions14/' + s.fbKey] = null;
      updates['savings14/' + s.fbKey] = null;
    });
    // NB: i 14-portalen ligger lærere på path 'teachers/' (ikke 'teachers14/')
    teachersInClass.forEach(t => { updates['teachers/' + t.fbKey + '/class'] = null; });

    if (Object.keys(updates).length) {
      await window._update(fbRef('/'), updates);
    }

    if (window._currentTeacher && window._currentTeacher.class === cls) {
      window._currentTeacher.class = null;
      if (typeof classFilter !== 'undefined') classFilter = '';
      if (typeof applyTeacherClassLock === 'function') applyTeacherClassLock();
    }

    currentDeleteClassName = null;
    closeModal('modal-delete-class');
    if (typeof renderClassManager === 'function') renderClassManager();
  } catch (e) {
    console.error('[Slett klasse feilet]', e);
    alert('Noe gikk galt under sletting: ' + (e.message || e));
  } finally {
    if (btn) { btn.disabled = false; btn.textContent = origText || 'Slett klasse'; btn.style.cursor = ''; }
    if (cancel) cancel.disabled = false;
  }
}


