function renderSaldoTable() {
  const tbody = document.getElementById('saldo-table-body');
  if (!tbody) return;
  const sav = window._savings || {};
  tbody.innerHTML = window._students.map(s => {
    const savBal = sav[s.fbKey]?.balance || 0;
    return `
    <tr>
      <td data-label="Elev"><strong>${s.firstname} ${s.lastname}</strong></td>
      <td data-label="Lommebok"><span class="balance-badge">🪙 ${s.balance}</span></td>
      <td data-label="Sparekonto"><span class="balance-badge" style="background:#dcfce7;color:#15803d;">🏦 ${savBal}</span></td>
      <td data-label=""><div class="balance-actions">
        <button class="btn btn-primary btn-sm" onclick="openSaldoModal('${s.fbKey}','add')">➕ Legg til</button>
        <button class="btn btn-ghost btn-sm"   onclick="openSaldoModal('${s.fbKey}','subtract')">➖ Trekk fra</button>
        <button class="btn btn-amber btn-sm"   onclick="openSaldoModal('${s.fbKey}','reset')">🔄 Nullstill</button>
      </div></td>
    </tr>`;
  }).join('');
}

function openSaldoModal(fbKey, action) {
  currentStudentId = fbKey; currentAction = action;
  const s = window._students.find(x => x.fbKey === fbKey);
  const labels = { add:'➕ Legg til mynter', subtract:'➖ Trekk fra mynter', set:'✏️ Sett saldo', reset:'🔄 Nullstill saldo' };
  document.getElementById('modal-saldo-title').textContent = labels[action] + ` – ${s.firstname}`;
  document.getElementById('modal-saldo-info').textContent  = `Nåværende saldo: 🪙 ${s.balance}`;
  document.getElementById('modal-saldo-amount').style.display = action === 'reset' ? 'none' : 'block';
  document.getElementById('modal-saldo').classList.add('open');
}
async function confirmSaldoAction() {
  const s = window._students.find(x => x.fbKey === currentStudentId);
  const amount = parseInt(document.getElementById('modal-saldo-amount').value) || 0;
  let newBal = s.balance;
  if (currentAction === 'add')           newBal = s.balance + amount;
  else if (currentAction === 'subtract') newBal = Math.max(0, s.balance - amount);
  else if (currentAction === 'set')      newBal = Math.max(0, amount);
  else if (currentAction === 'reset')    newBal = 0;
  await window._update(fbRef('students14/' + currentStudentId), { balance: newBal });
  // Nullstill også sparekonto når hovedkonto nullstilles
  if (currentAction === 'reset') {
    await window._update(fbRef('savings14/' + currentStudentId), { balance: 0 });
  }
  closeModal('modal-saldo');
}
function openBulkModal(action) {
  bulkAction = action;
  const labels = {
    add:    '➕ Legg til mynter – alle',
    salary: '💼 Utbetal ukentlig lønn – 20 % skatt',
    reset:  '🔄 Nullstill saldo – alle'
  };
  document.getElementById('modal-bulk-title').textContent = labels[action] || action;
  document.getElementById('bulk-amount-row').style.display = action === 'reset' ? 'none' : 'block';
  const ti = document.getElementById('bulk-tax-info');
  if (action === 'salary') {
    // Sjekk om det finnes aktive sparemål for noen av de berørte klassene
    const cls = document.getElementById('bulk-class').value;
    const targetClasses = cls
      ? [cls]
      : (window._currentTeacher?.role === 'admin'
          ? ['1. klasse','2. klasse','3. klasse','4. klasse']
          : [window._currentTeacher?.class].filter(Boolean));
    const hasActive = targetClasses.some(c =>
      (window._classGoals || []).some(g => !g.completed && g.class === c)
    );
    ti.innerHTML = hasActive
      ? '🏛️ <strong>20 % skatt</strong> trekkes fra brutto. Hvis eleven har valgt et sparemål, går skatten dit. Ellers fordeles den jevnt på alle aktive sparemål i elevens klasse.'
      : '⚠️ Ingen aktive sparemål for de valgte klassene – skatten <strong>holdes tilbake</strong>. Opprett et sparemål per klasse for at skatten skal komme til nytte.';
    ti.style.display = 'block';
  } else {
    ti.style.display = 'none';
  }
  document.getElementById('modal-bulk').classList.add('open');
}
async function confirmBulkAction() {
  // Anti-dobbeltklikk-vakt: hvis denne fortsatt kjører fra forrige klikk,
  // ignorer nye trykk. Tidligere bug: en utbetaling som tar 1-3 sekunder
  // (mange Firebase-kall i loop) lot læreren klikke "Bekreft" flere
  // ganger og dermed utbetale lønn dobbelt eller trippelt.
  if (window._bulkActionRunning) return;
  window._bulkActionRunning = true;

  // Lås knappen visuelt slik at læreren skjønner at noe skjer
  const confirmBtn = document.querySelector('#modal-bulk .btn-primary');
  const cancelBtn  = document.querySelector('#modal-bulk .btn-ghost');
  const origConfirmText = confirmBtn ? confirmBtn.textContent : '';
  if (confirmBtn) {
    confirmBtn.disabled = true;
    confirmBtn.textContent = '⏳ Behandler…';
    confirmBtn.style.opacity = '0.6';
    confirmBtn.style.cursor = 'wait';
  }
  if (cancelBtn) cancelBtn.disabled = true;

  try {
    const cls    = document.getElementById('bulk-class').value;
    const amount = parseInt(document.getElementById('bulk-amount').value) || 0;
    const updates = {};
    const targets = window._students.filter(s => !cls || s.class === cls);

    // Per-mål skatt-akkumulering for lønn
    const goalsByKey = Object.fromEntries((window._classGoals || []).map(g => [g.fbKey, g]));
    const activeGoalsByClass = {};
    (window._classGoals || []).forEach(g => {
      if (g.completed || !g.class) return;
      if (!activeGoalsByClass[g.class]) activeGoalsByClass[g.class] = [];
      activeGoalsByClass[g.class].push(g);
    });
    const taxPerGoal = {};

    for (const s of targets) {
      const cur = s.balance || 0;
      let newBal = cur, txDesc = '', txAmt = 0, txIcon = '💰';
      if (bulkAction === 'add') {
        newBal = cur + amount;
        txDesc = 'Ekstra fra lærer';
        txAmt  = amount;
        txIcon = '🎁';
      } else if (bulkAction === 'salary') {
        const taxAmt = Math.floor(amount * 0.20);
        const net    = amount - taxAmt;
        newBal = cur + net;
        txDesc = 'Ukentlig lønn (netto etter 20 % skatt)';
        txAmt  = net;
        txIcon = '💼';
        if (taxAmt > 0) {
          const chosen = s.chosenGoalKey ? goalsByKey[s.chosenGoalKey] : null;
          const goalMatchesClass = chosen && (!chosen.class || chosen.class === s.class);
          if (chosen && !chosen.completed && goalMatchesClass) {
            taxPerGoal[chosen.fbKey] = (taxPerGoal[chosen.fbKey] || 0) + taxAmt;
          } else {
            const classGoals = activeGoalsByClass[s.class] || [];
            if (classGoals.length > 0) {
              const perGoal = Math.floor(taxAmt / classGoals.length);
              const remainder = taxAmt - (perGoal * classGoals.length);
              classGoals.forEach((g, i) => {
                const share = perGoal + (i < remainder ? 1 : 0);
                if (share > 0) taxPerGoal[g.fbKey] = (taxPerGoal[g.fbKey] || 0) + share;
              });
            }
          }
        }
      } else if (bulkAction === 'reset') {
        newBal = 0;
        txDesc = 'Saldo nullstilt';
        txAmt  = -cur;
        txIcon = '🔄';
        updates['savings14/'+s.fbKey+'/balance'] = 0;
      }
      updates['students14/'+s.fbKey+'/balance'] = Math.max(0, newBal);
      if (txAmt !== 0) {
        await logTx14(s.fbKey, txAmt > 0 ? 'income' : 'expense', txIcon, txDesc, txAmt);
      }
    }

    // Skriv per-mål skattetillegg inn i samme batch
    for (const [fbKey, addAmt] of Object.entries(taxPerGoal)) {
      const g = goalsByKey[fbKey];
      if (!g) continue;
      const ns = (g.saved || 0) + addAmt;
      updates['classGoals14/' + fbKey + '/saved'] = ns;
      if (ns >= g.target) updates['classGoals14/' + fbKey + '/completed'] = true;
    }

    await window._update(fbRef('/'), updates);
  } catch (e) {
    console.error('[Bulk-action feilet]', e);
    alert('Noe gikk galt: ' + (e.message || e) + '\n\nPrøv igjen, eller sjekk transaksjonsloggen for å se hva som rakk å skje.');
  } finally {
    if (confirmBtn) {
      confirmBtn.disabled = false;
      confirmBtn.textContent = origConfirmText || 'Bekreft';
      confirmBtn.style.opacity = '';
      confirmBtn.style.cursor = '';
    }
    if (cancelBtn) cancelBtn.disabled = false;
    window._bulkActionRunning = false;
    closeModal('modal-bulk');
  }
}
function openDeleteModal(fbKey, name) {
  currentStudentId = fbKey;
  document.getElementById('modal-delete-text').textContent = `Er du sikker på at du vil slette ${name}?`;
  document.getElementById('modal-delete').classList.add('open');
}
async function confirmDelete() { await window._remove(fbRef('students14/' + currentStudentId)); closeModal('modal-delete'); }

