// ══════════════════════════════════════════════════════════
// HANDLELISTE
// ══════════════════════════════════════════════════════════
function renderHandlelisteSelect() {
  const el = document.getElementById('handleliste-select');
  if (!el) return;
  el.innerHTML = window._groceries.map(g => `
    <div class="grocery-item" onclick="this.classList.toggle('selected')" data-key="${g.fbKey}">
      <div class="grocery-emoji">${g.emoji}</div>
      <div class="grocery-name">${g.name}</div>
    </div>`).join('');
}
function generateShoppingList() {
  // Trigger forhåndsvisning av side 1. Selve datasettet bygges felles
  // for forhåndsvisning og utskrift slik at de garantert er identiske.
  renderListPreview();
}
function generateRandomList() {
  // Når læreren ber om «tilfeldig», nullstiller vi valget i UI og lar
  // den delte generatoren produsere helt tilfeldige lister.
  document.querySelectorAll('#handleliste-select .grocery-item.selected').forEach(e => e.classList.remove('selected'));
  // Tving nytt seed/pool så lærere kan trykke flere ganger og få noe nytt
  window._lastShoppingListPages = null;
  renderListPreview();
}
function getRandom(arr, n)    { return [...arr].sort(() => Math.random()-.5).slice(0, Math.min(n, arr.length)); }

// ══════════════════════════════════════════════════════════
// FELLES generator: produserer ferdige sider for handlelister.
// Brukes av BÅDE forhåndsvisning og utskrift — slik at de viser
// nøyaktig samme innhold (ikke bare samme oppsett).
//
// Returnerer { sn, count, pages, pagesData: [[a,b], [a,b], ...] }
// hvor hver pages-rad er to lister (venstre + høyre på A4-arket).
// ══════════════════════════════════════════════════════════
function generateShoppingListPages() {
  const sn    = document.getElementById('list-student').value;
  const sel   = [...document.querySelectorAll('#handleliste-select .grocery-item.selected')].map(e => e.dataset.key);
  const count = Math.min(8, parseInt(document.getElementById('list-count').value) || 5);
  const pages = Math.max(1, Math.min(20, parseInt(document.getElementById('list-pages').value) || 1));
  const pool  = sel.length ? window._groceries.filter(g => sel.includes(g.fbKey)) : (window._groceries || []);

  const pagesData = [];
  for (let p = 0; p < pages; p++) {
    pagesData.push([ getRandom(pool, count), getRandom(pool, count) ]);
  }
  return { sn, count, pages, pool, pagesData };
}

