function renderListPreview() {
  // Generer ALLE sidene NÅ og cache dem på window, slik at både
  // forhåndsvisning og utskrift bruker samme datasett.
  const data = generateShoppingListPages();
  if (!data.pool.length) { alert('Ingen varer tilgjengelig.'); return; }
  window._lastShoppingListPages = data;

  const [a, b] = data.pagesData[0];
  const pageHTML = buildShoppingListPageHTML(a, b, data.sn);

  document.getElementById('handleliste-preview').style.display = 'block';

  // Scope MYNTLAND_BUTIKK_CSS til .preview-scaler ved å prefikse hver selektor.
  // Fjerner først kommentarer og regler som ikke gir mening i forhåndsvisningen
  // (:root, html/body, @page), og prefikser deretter resten med .preview-scaler.
  function scopePreviewCss(css) {
    // VIKTIG: strip CSS-kommentarer først — ellers blir /*…*/ behandlet som
    // selektor av regexen under, noe som ødelegger reglene rundt.
    css = css.replace(/\/\*[\s\S]*?\*\//g, '');
    // Strip ut regler vi ikke vil ha
    css = css
      .replace(/:root\s*\{[^}]*\}/g, '')
      .replace(/html\s*,\s*body\s*\{[^}]*\}/g, '')
      .replace(/@page\s*\{[^}]*\}/g, '');
    // Prefiks alle selektorer på toppnivå med .preview-scaler
    return css.replace(/(^|\})\s*([^{}]+)\{/g, function(_m, close, selectors) {
      var prefixed = selectors.split(',').map(function(s){
        s = s.trim();
        if (!s) return s;
        if (s.indexOf('.preview-scaler') === 0) return s;
        return '.preview-scaler ' + s;
      }).join(', ');
      return close + ' ' + prefixed + '{';
    });
  }
  var scopedBokCss = scopePreviewCss(MYNTLAND_BUTIKK_CSS);

  document.getElementById('handleliste-content').innerHTML =
    `<style>
       .preview-stage{position:relative;width:100%;background:#EFE9D8;border-radius:12px;padding:12px;overflow:hidden}
       .preview-scaler{transform-origin:top left;background:white;box-shadow:0 4px 16px rgba(42,31,61,.18);position:relative;--gull:#C99517;--gull-lys:#FFF7DD;--blekk:#2A1F3D;--blekk-myk:#4A3D5C;--pergament:#FBF2D6;font-family:'Nunito',sans-serif;color:#2A1F3D}
       ${scopedBokCss}
       /* Override: lærerportalens hoved-CSS har «.page{display:none}» (kun
          .page.active vises). Det treffer også .page-elementet inni
          forhåndsvisningen. Tving det synlig her. */
       .preview-scaler .page,
       .preview-scaler .page.landscape{display:block !important}
     </style>
     <div class="preview-stage" id="preview-stage">
       <div class="preview-scaler" id="preview-scaler">${pageHTML}</div>
     </div>
     <p style="font-size:.78rem;color:var(--muted);margin-top:.75rem;">💡 Forhåndsvisning av side 1 — nøyaktig det utskriften vil generere. Totalt ${data.pages} side${data.pages>1?'r':''}${data.pages>1?' (hver med to forskjellige lister)':''}. Trykk «Skriv ut» for full utskrift.</p>`;

  // Skaler ned slik at hele A4 landscape (297mm bred) passer i kortet
  requestAnimationFrame(() => {
    const stage = document.getElementById('preview-stage');
    const scaler = document.getElementById('preview-scaler');
    if (!stage || !scaler) return;
    // 297mm i piksler ≈ 297 * 96 / 25.4 ≈ 1122.5 px
    const A4_LANDSCAPE_WIDTH_PX  = 297 * 96 / 25.4;
    const A4_LANDSCAPE_HEIGHT_PX = 210 * 96 / 25.4;
    const fit = () => {
      const available = stage.clientWidth - 24; // minus padding
      const scale = Math.min(1, available / A4_LANDSCAPE_WIDTH_PX);
      scaler.style.transform = `scale(${scale})`;
      scaler.style.width  = A4_LANDSCAPE_WIDTH_PX + 'px';
      scaler.style.height = A4_LANDSCAPE_HEIGHT_PX + 'px';
      // Reserver høyde på containeren etter skalering
      stage.style.height = (A4_LANDSCAPE_HEIGHT_PX * scale + 24) + 'px';
    };
    fit();
    // Re-fit ved vindusendring (lytteren legges på én gang)
    if (!window._previewResizeHooked) {
      window._previewResizeHooked = true;
      window.addEventListener('resize', () => {
        if (document.getElementById('preview-scaler')) fit();
      });
    }
  });
}

