// ── Custom Rewards ─────────────────────────────────────────────────────────
async function addCustomReward() {
  const amount = parseInt(document.getElementById('custom-qr-amount').value) || 0;
  const desc   = document.getElementById('custom-qr-desc').value.trim();
  const alertEl = document.getElementById('custom-reward-alert');
  if (!amount || amount < 1) {
    alertEl.innerHTML = '<div class="alert alert-error">⚠️ Skriv inn et gyldig beløp.</div>'; return;
  }
  if (!ready()) { alertEl.innerHTML = '<div class="alert alert-error">⚠️ Firebase ikke klar.</div>'; return; }
  await window._set(window._push(fbRef('customRewards14')), {
    amount, desc: desc || `+${amount} mynter`, created: Date.now()
  });
  document.getElementById('custom-qr-amount').value = '25';
  document.getElementById('custom-qr-desc').value   = '';
  alertEl.innerHTML = `<div class="alert alert-success">✅ Belønning på 🪙 ${amount} lagt til!</div>`;
  setTimeout(() => alertEl.innerHTML = '', 2500);
}

function renderCustomRewards() {
  const el = document.getElementById('custom-rewards-list');
  if (!el) return;
  if (!window._customRewards.length) {
    el.innerHTML = '<p style="color:var(--muted);font-size:.85rem;">Ingen egendefinerte belønninger ennå.</p>';
    return;
  }
  el.innerHTML = window._customRewards.map((r, idx) => `
    <div style="display:flex;align-items:center;gap:12px;padding:.9rem 1rem;background:var(--bg);border-radius:12px;margin-bottom:8px;">
      <div style="width:36px;height:36px;background:var(--green-light);border-radius:9px;display:flex;align-items:center;justify-content:center;font-family:'Fredoka One',cursive;color:var(--green-dark);font-size:.8rem;flex-shrink:0;">🪙${r.amount}</div>
      <div style="flex:1;">
        <div style="font-weight:800;font-size:.9rem;">+${r.amount} 🪙</div>
        <div style="font-size:.78rem;color:var(--muted);">${r.desc}</div>
      </div>
      <div id="mini-qr-${r.fbKey}" style="width:60px;height:60px;flex-shrink:0;"></div>
      <div style="display:flex;flex-direction:column;gap:4px;">
        <button class="btn btn-primary btn-sm" onclick="printCustomReward('${r.fbKey}')">🖨️</button>
        <button class="btn btn-coral btn-sm"   onclick="deleteCustomReward('${r.fbKey}')">🗑️</button>
      </div>
    </div>`).join('');
  // Render mini QRs
  window._customRewards.forEach(r => {
    const el = document.getElementById('mini-qr-' + r.fbKey);
    if (el && !el.children.length) {
      try { new QRCode(el, { text: JSON.stringify({type:'reward', amount:r.amount, desc:r.desc}), width:60, height:60, correctLevel:QRCode.CorrectLevel.L }); } catch(e){}
    }
  });
}

async function deleteCustomReward(fbKey) {
  if (!confirm('Slett denne belønningen?')) return;
  await window._remove(fbRef('customRewards14/' + fbKey));
}

function printCustomReward(fbKey) {
  const r = window._customRewards.find(x => x.fbKey === fbKey);
  if (!r) return;
  _printRewardCards([r]);
}

function printAllCustomRewards() {
  if (!window._customRewards.length) { alert('Ingen belønninger å skrive ut.'); return; }
  _printRewardCards(window._customRewards);
}

