// ════════════════════════════════════════════════════════════════════
// PDF-DOWNLOAD-BANNER — gjenbrukbar helper
//
// Skoleskrivere takler en ferdig PDF mye bedre enn en live utskrift
// fra nettleseren (live = mange ulike effekter må prosesseres on the
// fly; PDF = alt er ferdig flatpresset og pakket). Derfor: i stedet
// for å auto-printe, viser vi et banner med instruksjon om å lagre
// som PDF først, og deretter sende PDF-en til skoleskriveren.
//
// Returnerer { bannerHTML, bannerCSS } som skal injiseres i popup-en
// før innholdet og inne i <style>-blokken.
// ════════════════════════════════════════════════════════════════════
window.buildPdfDownloadBanner = function(title, opts) {
  opts = opts || {};
  var twoSided  = !!opts.twoSided;
  var landscape = !!opts.landscape;
  var heading = twoSided ? 'Slik skriver du ut – tosidig' : 'Slik skriver du ut';
  var steps = ''
    + '<li>Trykk <strong>«Skriv ut»</strong> nederst.</li>'
    + '<li>Velg skriveren din — eller <strong>«Lagre som PDF»</strong> om du vil skrive ut senere.</li>'
    + '<li>Sett skala til <strong>100 %</strong> (ikke «tilpass til side»), og slå på <strong>«skriv ut bakgrunnsgrafikk»</strong> så fargene blir med.</li>';
  if (twoSided)  steps += '<li>Velg <strong>tosidig utskrift</strong> og <strong>«vend langs lang kant»</strong>, så baksiden havner rett bak forsiden.</li>';
  if (landscape) steps += '<li>📐 Velg <strong>Liggende</strong> i dialogen — arket er laget liggende.</li>';
  steps += twoSided
    ? '<li>Klipp langs de stiplede linjene på forsidearket.</li>'
    : '<li>Klipp langs de stiplede linjene.</li>';
  var bannerHTML = ''
    + '<div class="print-info-banner"><div class="pib-inner">'
    +   '<div class="pib-title">🖨️ ' + heading + '</div>'
    +   '<ol class="pib-list">' + steps + '</ol>'
    +   '<button class="pib-print-btn" onclick="window.print()">🖨️ Skriv ut nå</button>'
    + '</div></div>';

  var bannerCSS = ''
    + '@media screen{'
    +   '.print-info-banner{position:fixed;top:0;left:0;right:0;background:#FFE89A;border-bottom:3px solid #2A1F3D;z-index:9999;padding:14px 20px;font-family:"Nunito",sans-serif;color:#2A1F3D;box-shadow:0 4px 12px rgba(0,0,0,.15)}'
    +   '.pib-inner{max-width:780px;margin:0 auto}'
    +   '.pib-title{font-family:"Bowlby One","Fredoka One",sans-serif;font-size:14pt;margin-bottom:8px;letter-spacing:.02em}'
    +   '.pib-list{margin:0 0 10px 22px;padding:0;font-size:10.5pt;line-height:1.55}'
    +   '.pib-list li{margin-bottom:3px}'
    +   '.pib-list strong{color:#2A1F3D}'
    +   '.pib-tip{font-size:10pt;color:#4A3D5C;margin-bottom:12px;padding:8px 12px;background:rgba(42,31,61,.06);border-radius:6px;border-left:3px solid #F5C849}'
    +   '.pib-print-btn{display:inline-block;background:#2A1F3D;color:#F5C849;border:none;padding:10px 24px;border-radius:8px;font-family:"Bowlby One","Fredoka One",sans-serif;font-size:11pt;letter-spacing:.04em;cursor:pointer;transition:all .15s}'
    +   '.pib-print-btn:hover{background:#1A1228;transform:translateY(-1px);box-shadow:0 4px 12px rgba(0,0,0,.2)}'
    +   'body{padding-top:260px}'
    + '}'
    + '@media print{.print-info-banner{display:none !important}body{padding-top:0 !important}}';

  return { bannerHTML: bannerHTML, bannerCSS: bannerCSS };
};

// ════════════════════════════════════════════════════════════════════
// QR-TIL-SVG — utskriftsvennlig, ingen ekstern PNG, ingen rasterisering
//
// Bruker qrcodejs (allerede lastet) til å beregne QR-mønsteret. Vi
// gjør to forsøk for robusthet:
//
//   1. Direkte tilgang til den interne QRCodeModel-en (`_oQRCode`)
//      som har isDark(row,col) og getModuleCount() — eksakt, ingen
//      gjetting. Dette er den foretrukne veien.
//
//   2. Fallback: les ut pikslene fra qrcodejs sin canvas-output, og
//      rekonstruér mønsteret. Brukes hvis interne objekter ikke er
//      tilgjengelige (eldre nettlesere, fremtidige bibliotekversjoner).
//
//   3. Siste utvei: ekstern PNG fra api.qrserver.com, slik det var
//      før. Trygt, men tyngre på printeren.
//
// Resultatet er vektor (ren svart/hvit SVG) på 1–3 KB per kort,
// vs. 5–30 KB for PNG som blir rasterisert til mye større bitmap når
// printeren tar over.
// ════════════════════════════════════════════════════════════════════
window.qrToSVG = function(payload, sizeMm, correctLevel) {
  sizeMm = sizeMm || 30;
  var text = typeof payload === 'string' ? payload : JSON.stringify(payload);
  // correctLevel: 'L' = 7%, 'M' = 15% (default), 'Q' = 25%, 'H' = 30%
  // L gir færre moduler → mindre PDF-filstørrelse. Trygt for digitalt rendrede QR
  // som ikke utsettes for slitasje.
  var ecLevel = (correctLevel && QRCode && QRCode.CorrectLevel && QRCode.CorrectLevel[correctLevel])
    ? QRCode.CorrectLevel[correctLevel]
    : (typeof QRCode !== 'undefined' ? QRCode.CorrectLevel.M : 1);

  function fallbackImg(reason) {
    var url = 'https://api.qrserver.com/v1/create-qr-code/?size=200x200&margin=2&data=' +
              encodeURIComponent(text);
    return '<img src="' + url + '" style="width:' + sizeMm + 'mm;height:' + sizeMm +
           'mm;display:block;" alt="QR" data-fallback="' + reason + '">';
  }

  if (typeof QRCode === 'undefined') return fallbackImg('no-lib');

  // Lag en QRCode-instans i en off-screen container.
  var tmp = document.createElement('div');
  tmp.style.cssText = 'position:absolute;left:-9999px;top:-9999px;visibility:hidden;width:200px;height:200px;';
  document.body.appendChild(tmp);

  var qr;
  try {
    qr = new QRCode(tmp, {
      text: text,
      width: 200, height: 200,
      correctLevel: ecLevel
    });
  } catch(e) {
    document.body.removeChild(tmp);
    return fallbackImg('qr-throw');
  }

  // ── Forsøk 1: bruk det interne QRCodeModel-objektet direkte ───────────
  var grid = null;
  var modules = 0;
  try {
    var model = qr._oQRCode;
    if (model && typeof model.getModuleCount === 'function' &&
        typeof model.isDark === 'function') {
      modules = model.getModuleCount();
      if (modules > 0) {
        grid = [];
        for (var r = 0; r < modules; r++) {
          var row = [];
          for (var c = 0; c < modules; c++) {
            row.push(model.isDark(r, c) ? 1 : 0);
          }
          grid.push(row);
        }
      }
    }
  } catch(e) { grid = null; }

  // ── Forsøk 2: les fra canvas hvis interne objektet ikke virket ────────
  if (!grid) {
    var canvas = tmp.querySelector('canvas');
    if (canvas) {
      try {
        var ctx = canvas.getContext('2d');
        var cw = canvas.width, ch = canvas.height;
        var data = ctx.getImageData(0, 0, cw, ch).data;
        function isDarkPx(x, y) {
          var i = (y * cw + x) * 4;
          return (data[i] + data[i+1] + data[i+2]) < 384;
        }
        // Finn første mørke piksel = topp-venstre av QR
        var startX = -1, startY = -1;
        for (var y = 0; y < ch && startY < 0; y++) {
          for (var x = 0; x < cw; x++) {
            if (isDarkPx(x, y)) { startX = x; startY = y; break; }
          }
        }
        if (startX >= 0) {
          // Mål modulstørrelse
          var ms = 0;
          while (startX + ms < cw && isDarkPx(startX + ms, startY)) ms++;
          if (ms >= 2) {
            modules = Math.round((cw - 2 * startX) / ms);
            if (modules >= 21 && modules <= 177) {
              grid = [];
              for (var ry = 0; ry < modules; ry++) {
                var rowG = [];
                var py = startY + Math.floor(ry * ms + ms / 2);
                for (var rx = 0; rx < modules; rx++) {
                  var px = startX + Math.floor(rx * ms + ms / 2);
                  rowG.push((px < cw && py < ch && isDarkPx(px, py)) ? 1 : 0);
                }
                grid.push(rowG);
              }
            }
          }
        }
      } catch(e) { grid = null; }
    }
  }

  document.body.removeChild(tmp);

  // ── Forsøk 3: ekstern PNG hvis alt feilet ─────────────────────────────
  if (!grid || !modules) return fallbackImg('extract-failed');

  // Bygg én sammensatt path — én "M x y h1 v1 h-1 z" per mørk modul.
  var pathParts = [];
  for (var ry2 = 0; ry2 < modules; ry2++) {
    for (var rx2 = 0; rx2 < modules; rx2++) {
      if (grid[ry2][rx2]) {
        pathParts.push('M' + rx2 + ',' + ry2 + 'h1v1h-1z');
      }
    }
  }

  // Quiet zone på 2 moduler — holder for skanning.
  var quiet = 2;
  var vb = modules + quiet * 2;
  // SVG-en får eksplisitt størrelse i mm (mest pålitelig på tvers av nettlesere
  // og PDF-eksport — CSS-prosent kan oppføre seg uforutsigbart i utskrift).
  // preserveAspectRatio holder QR-en sentrert hvis container er litt større.
  return '<svg xmlns="http://www.w3.org/2000/svg" width="' + sizeMm + 'mm" height="' + sizeMm + 'mm" viewBox="' +
         (-quiet) + ' ' + (-quiet) + ' ' + vb + ' ' + vb +
         '" preserveAspectRatio="xMidYMid meet"' +
         ' style="display:block;background:#fff;shape-rendering:crispEdges">' +
         '<path d="' + pathParts.join('') + '" fill="#000"/></svg>';
};

// ════════════════════════════════════════════════════════════════════
// MYNTLAND BANKKORT — shared helper
// Bygger en komplett HTML-side med 8 forsider + 8 baksider per A4-side.
// Brukes av begge lærerportaler (1–4 og 5–7) til utskrift av bankkort.
// ════════════════════════════════════════════════════════════════════
window.buildMyntlandBankCardsHTML = function(students, opts) {
  opts = opts || {};
  var showPin   = !!opts.showPin;
  var getAvatar = opts.getAvatarSVG;            // beholdt for kompatibilitet
  var title     = opts.title || 'Myntland · Bankkort';
  var THEMES = ['theme-gull','theme-turkis','theme-korall','theme-lilla','theme-lime','theme-skog'];

  function hashStr(str) {
    var h = 0, i; str = String(str||'');
    for (i = 0; i < str.length; i++) h = ((h<<5) - h) + str.charCodeAt(i);
    return Math.abs(h);
  }
  function fakePAN(s) {
    var h = hashStr((s.fbKey||'') + (s.firstname||'') + (s.lastname||''));
    var last4 = String(h % 10000).padStart(4, '0');
    return '4900 41•• •••• ' + last4;
  }
  function escapeHTML(s) {
    return String(s||'').replace(/[&<>"']/g, function(c){
      return ({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'})[c];
    });
  }

  // QR: inline-vektor hvis qrToSVG finnes (1.–4.-portalen), ellers QR-bilde-API.
  // Selve kortdesignen blir lik uansett — kun teknikken bak QR-en varierer.
  function qrMarkup(payload) {
    if (typeof window.qrToSVG === 'function') return window.qrToSVG(payload, 16, 'L');
    var url = 'https://api.qrserver.com/v1/create-qr-code/?size=240x240&margin=0&data='
      + encodeURIComponent(JSON.stringify(payload));
    return '<img src="' + url + '" alt="QR" crossorigin="anonymous">';
  }

  // Myntland-mynt — logo-emblem i båndet og på baksiden. Ren vektor.
  function coinSVG() {
    return '<svg viewBox="0 0 60 60" preserveAspectRatio="xMidYMid meet" xmlns="http://www.w3.org/2000/svg">'
      + '<circle cx="30" cy="30" r="24" fill="#F5C849" stroke="#2A1F3D" stroke-width="2.5"/>'
      + '<circle cx="30" cy="30" r="20" fill="none" stroke="#C99517" stroke-width="1"/>'
      + '<circle cx="30" cy="30" r="17" fill="none" stroke="#2A1F3D" stroke-width=".6" stroke-dasharray="1.5,1.5" opacity=".55"/>'
      + '<text x="30" y="39" text-anchor="middle" font-family="Fraunces, Georgia, serif" font-size="24" font-weight="900" font-style="italic" fill="#2A1F3D">M</text>'
      + '</svg>';
  }
  // Liten chip — gir kortet et umiddelbart bankkort-preg. Ren vektor.
  function chipSVG() {
    return '<svg viewBox="0 0 46 34" preserveAspectRatio="xMidYMid meet" xmlns="http://www.w3.org/2000/svg">'
      + '<rect x="1" y="1" width="44" height="32" rx="5" fill="#E9BE44" stroke="#B8901F" stroke-width="1.5"/>'
      + '<line x1="1" y1="12.3" x2="45" y2="12.3" stroke="#B8901F" stroke-width="1.2"/>'
      + '<line x1="1" y1="21.7" x2="45" y2="21.7" stroke="#B8901F" stroke-width="1.2"/>'
      + '<line x1="16" y1="1" x2="16" y2="33" stroke="#B8901F" stroke-width="1.2"/>'
      + '<line x1="30" y1="1" x2="30" y2="33" stroke="#B8901F" stroke-width="1.2"/>'
      + '</svg>';
  }

  function frontHTML(s, idx) {
    var theme   = THEMES[idx % THEMES.length];
    var display = escapeHTML((s.firstname||'') + ' ' + (s.lastname||'').charAt(0) + '.');
    var pinHTML = (showPin && s.pin)
      ? '<span class="pin-val">' + escapeHTML(s.pin) + '</span>'
      : '<span class="pin-val pin-blank">– – – –</span>';
    var klasse = s.class ? 'KLASSE ' + escapeHTML(s.class) : '';
    return ''
      + '<div class="card-slot">'
      +   '<div class="bank ' + theme + '">'
      +     '<div class="band">'
      +       '<span class="brand">MYNTLAND</span>'
      +       '<span class="emblem">' + coinSVG() + '</span>'
      +     '</div>'
      +     '<div class="body">'
      +       '<div class="r-top">'
      +         '<div class="top-left">'
      +           '<span class="chip">' + chipSVG() + '</span>'
      +           '<span class="klasse">' + klasse + '</span>'
      +         '</div>'
      +         '<div class="qr">' + qrMarkup({ type:'login', fbKey:s.fbKey }) + '</div>'
      +       '</div>'
      +       '<div class="cardnum">' + fakePAN(s) + '</div>'
      +       '<div class="r-bot">'
      +         '<div class="holder"><span class="lbl">KORTHOLDER</span><span class="navn">' + display + '</span></div>'
      +         '<div class="pin"><span class="lbl">PIN</span>' + pinHTML + '</div>'
      +       '</div>'
      +     '</div>'
      +   '</div>'
      + '</div>';
  }
  function backHTML() {
    return ''
      + '<div class="card-slot">'
      +   '<div class="back">'
      +     '<div class="back-coin">' + coinSVG() + '</div>'
      +     '<div class="back-logo">MYNTLAND</div>'
      +     '<div class="back-sub">Klassens sparebank</div>'
      +     '<div class="back-name"><span class="bn-lbl">ELEVENS NAVN</span><span class="bn-line"></span></div>'
      +   '</div>'
      + '</div>';
  }

  // Bygg sider — 8 kort per A4, forside + bakside annenhver side.
  var pagesHTML = '';
  var emptySlot = '<div class="card-slot card-slot-empty"></div>';
  for (var i = 0; i < students.length; i += 8) {
    var chunk = students.slice(i, i + 8);
    var fronts = chunk.map(function(s, j){ return frontHTML(s, i + j); }).join('');
    for (var fp = chunk.length; fp < 8; fp++) fronts += emptySlot;
    // Like mange baksider som forsider. Plasseringen SPEILES horisontalt
    // (kol 0 ↔ kol 1, dvs. slot k ↔ slot k XOR 1) slik at hver bakside lander
    // bak sin forside når sida vendes ved tosidig utskrift med «vend langs
    // lang kant». Resten av baksidearket er tomt — ingen sløsing.
    var hasBack = new Array(8).fill(false);
    for (var bk = 0; bk < chunk.length; bk++) hasBack[bk ^ 1] = true;
    var backs = '';
    for (var k = 0; k < 8; k++) backs += hasBack[k] ? backHTML() : emptySlot;
    pagesHTML += '<div class="page"><div class="card-grid">' + fronts + '</div></div>';
    pagesHTML += '<div class="page back-page"><div class="card-grid">' + backs + '</div></div>';
  }

  var css = ''
    + '@page{size:A4 portrait;margin:0}'
    + '*{box-sizing:border-box}'
    + 'html,body{margin:0;padding:0;background:white;font-family:"Nunito",sans-serif;color:#2A1F3D;-webkit-print-color-adjust:exact;print-color-adjust:exact}'
    + '.page{width:210mm;height:273mm;max-height:273mm;margin:0 auto;position:relative;overflow:hidden;page-break-after:always;break-after:page;background:white}'
    + '.page:last-of-type{page-break-after:auto}'
    + '.card-grid{position:absolute;inset:4mm 0 4mm 0;display:grid;grid-template-columns:repeat(2,96mm);grid-template-rows:repeat(4,66mm);gap:0;justify-content:center}'
    + '.card-slot{position:relative;padding:0}'
    + '.card-slot-empty{visibility:hidden}'
    /* Klippelinjer — KUN på forsidearket, aldri på baksiden */
    + '.page:not(.back-page) .card-slot{border-right:1px dashed #B0A8C0;border-bottom:1px dashed #B0A8C0}'
    + '.page:not(.back-page) .card-grid>.card-slot:nth-child(2n){border-right:none}'
    + '.page:not(.back-page) .card-grid>.card-slot:nth-child(n+7){border-bottom:none}'
    /* FORSIDE — dus temabakgrunn, farget bånd */
    + '.bank{width:100%;height:100%;background:var(--cbg,#FFFFFF);display:grid;grid-template-rows:9mm 1fr;overflow:hidden}'
    + '.bank .band{background:var(--ca,#F5C849);display:flex;align-items:center;justify-content:space-between;padding:0 5mm}'
    + '.bank .band .brand{font-family:"Bowlby One",sans-serif;font-size:9pt;letter-spacing:.06em;color:#2A1F3D}'
    + '.bank .band .emblem{width:6mm;height:6mm}'
    + '.bank .band .emblem svg{display:block;width:100%;height:100%}'
    + '.bank.theme-korall .band .brand,.bank.theme-lilla .band .brand,.bank.theme-skog .band .brand{color:#FBF2D6}'
    + '.bank .body{display:grid;grid-template-rows:auto auto 1fr;padding:4mm 5mm}'
    + '.bank .r-top{display:flex;justify-content:space-between;align-items:flex-start}'
    + '.bank .top-left{display:flex;flex-direction:column;gap:2.5mm}'
    + '.bank .chip{display:block}'
    + '.bank .chip svg{display:block;width:11mm;height:8.1mm}'
    + '.bank .klasse{font-family:"Nunito",sans-serif;font-weight:800;font-size:8pt;letter-spacing:.1em;color:#6E6480}'
    + '.bank .qr{width:20mm;height:20mm;background:#fff;border:.3mm solid #2A1F3D;border-radius:1.5mm;padding:2mm}'
    + '.bank .qr svg,.bank .qr img{display:block;width:100%;height:100%}'
    + '.bank .cardnum{margin-top:3mm;font-family:"JetBrains Mono",monospace;font-weight:700;font-size:12pt;letter-spacing:.06em;color:#2A1F3D;white-space:nowrap}'
    + '.bank .r-bot{display:flex;justify-content:space-between;align-items:flex-end;gap:3mm}'
    + '.bank .holder{display:flex;flex-direction:column;min-width:0}'
    + '.bank .pin{display:flex;flex-direction:column}'
    + '.bank .lbl{font-family:"Nunito",sans-serif;font-weight:800;font-size:7pt;letter-spacing:.16em;color:#6E6480;margin-bottom:.6mm}'
    + '.bank .navn{font-family:"Nunito",sans-serif;font-weight:900;font-size:13pt;line-height:1;color:#2A1F3D;white-space:nowrap;overflow:hidden;text-overflow:ellipsis}'
    + '.bank .pin-val{font-family:"JetBrains Mono",monospace;font-weight:700;font-size:12pt;letter-spacing:.18em;color:#2A1F3D;line-height:1}'
    + '.bank .pin-val.pin-blank{color:#6E6480;opacity:.55}'
    /* TEMA — bånd-farge (--ca) + dus bakgrunnsfarge (--cbg) */
    + '.bank.theme-gull{--ca:#F5C849;--cbg:#FBF4DD}'
    + '.bank.theme-turkis{--ca:#2DC4C4;--cbg:#E1F4F3}'
    + '.bank.theme-korall{--ca:#C13D2F;--cbg:#F8E7E1}'
    + '.bank.theme-lilla{--ca:#6B5BA8;--cbg:#ECE9F4}'
    + '.bank.theme-lime{--ca:#B8DA3B;--cbg:#F1F4DC}'
    + '.bank.theme-skog{--ca:#2F6B4A;--cbg:#E4EDE7}'
    /* BAKSIDE — felles for alle kort, med skrivefelt for elevens navn */
    + '.back{width:100%;height:100%;background:#FBF2D6;display:flex;flex-direction:column;align-items:center;justify-content:center;padding:5mm;text-align:center}'
    + '.back .back-coin{width:15mm;height:15mm}'
    + '.back .back-coin svg{display:block;width:100%;height:100%}'
    + '.back .back-logo{font-family:"Bowlby One",sans-serif;font-size:13pt;color:#2A1F3D;letter-spacing:.04em;margin-top:2mm}'
    + '.back .back-sub{font-family:"Fraunces",serif;font-style:italic;font-weight:900;font-size:8.5pt;color:#6E6480;letter-spacing:.06em;margin-top:1mm}'
    + '.back .back-name{width:74mm;background:#fff;border:.3mm solid #D8C9A0;border-radius:2mm;padding:2.4mm 4mm 2mm;margin-top:5mm}'
    + '.back .bn-lbl{display:block;font-family:"Nunito",sans-serif;font-weight:800;font-size:6.5pt;letter-spacing:.16em;color:#6E6480}'
    + '.back .bn-line{display:block;border-bottom:.4mm solid #B0A8C0;height:5mm;margin-top:.6mm}';

  // Felles utskriftsforklaring (tosidig) — samme tekst i begge portaler.
  var _bb = window.buildPdfDownloadBanner('', { twoSided: true });
  var infoBanner = _bb.bannerHTML;
  var bannerCSS  = _bb.bannerCSS;

  return '<!DOCTYPE html><html lang="nb"><head><meta charset="UTF-8"><style>img.myntico{height:1em;width:auto;vertical-align:-0.16em;margin:0 .04em}</style><script>(function(){var U=(window.opener&&window.opener.__MYNTCOIN__)||"https://myntland.no/mynt.webp";var E="🪙";function C(n){if(n.nodeType===3){var v=n.nodeValue;if(!v||v.indexOf(E)<0)return;var p=n.parentNode;if(!p)return;var t=p.nodeName;if(t==="SCRIPT"||t==="STYLE"||t==="TEXTAREA")return;var a=v.split(E),f=document.createDocumentFragment();for(var i=0;i<a.length;i++){if(a[i])f.appendChild(document.createTextNode(a[i]));if(i<a.length-1){var m=document.createElement("img");m.className="myntico";m.src=U;m.alt="mynt";f.appendChild(m);}}p.replaceChild(f,n);}else if(n.nodeType===1){var k=[].slice.call(n.childNodes);for(var j=0;j<k.length;j++)C(k[j]);}}function R(){try{C(document.body);}catch(e){}}if(document.readyState==="loading"){document.addEventListener("DOMContentLoaded",R);}else{R();}})();</script><title>' + escapeHTML(title) + '</title>'
    + '<link rel="preconnect" href="https://fonts.googleapis.com">'
    + '<link rel="preconnect" href="https://fonts.gstatic.com" crossorigin>'
    + '<link href="https://fonts.googleapis.com/css2?family=Fraunces:ital,opsz,wght@0,9..144,700;0,9..144,900;1,9..144,700;1,9..144,900&family=Nunito:wght@400;600;700;800;900&family=Bowlby+One&family=JetBrains+Mono:wght@500;700&display=swap" rel="stylesheet">'
    + '<style>' + css + bannerCSS + '</style>'
    + '</head><body>' + infoBanner + pagesHTML + '</body></html>';
};

// ══════════════════════════════════════════════════════════
// BANKKORT PDF — Myntland-design (forside + bakside annenhver side)
// Elevvalget gjøres i modalen `modal-card-select` (avhukingsbokser
// per klasse). Selve utskriften henter alle avhukede elever derfra.
// ══════════════════════════════════════════════════════════
function cs14Esc(s){
  return String(s==null?'':s).replace(/&/g,'&amp;').replace(/"/g,'&quot;')
    .replace(/</g,'&lt;').replace(/>/g,'&gt;');
}
function openCardSelect(){
  const t=window._currentTeacher;
  let students=(window._students||[]).slice();
  if(t?.class && t.role!=='admin') students=students.filter(s=>s.class===t.class);
  students.sort((a,b)=>(a.class||'').localeCompare(b.class||'')||(a.firstname||'').localeCompare(b.firstname||'','no'));
  if(!students.length){ alert('Ingen elever å skrive ut kort for.'); return; }

  // Grupper per klasse
  const byClass={};
  students.forEach(s=>{ (byClass[s.class||'(uten klasse)']=byClass[s.class||'(uten klasse)']||[]).push(s); });
  const classes=Object.keys(byClass).sort();

  const groupsHTML=classes.map(cls=>{
    const rows=byClass[cls].map(s=>{
      const navn=`${cs14Esc(s.firstname||'')} ${cs14Esc(s.lastname||'')}`;
      return `<label class="cs-row" style="display:flex;align-items:center;gap:10px;padding:7px 12px;border-bottom:1px solid var(--bg);cursor:pointer;">
        <input type="checkbox" class="cs-cb" data-fbkey="${cs14Esc(s.fbKey)}" data-class="${cs14Esc(cls)}" checked onchange="cardSelectUpdateCount()" style="width:18px;height:18px;cursor:pointer;flex:0 0 auto;">
        <span style="flex:1;font-weight:700;">${navn}</span>
      </label>`;
    }).join('');
    return `<div class="cs-class-group" style="margin-bottom:.6rem;border:1.5px solid var(--border);border-radius:10px;overflow:hidden;">
      <div style="display:flex;align-items:center;gap:8px;padding:8px 12px;background:var(--bg);border-bottom:1.5px solid var(--border);flex-wrap:wrap;">
        <span class="class-badge">${cs14Esc(cls)}</span>
        <span style="flex:1;font-size:.78rem;color:var(--muted);font-weight:700;">${byClass[cls].length} elever</span>
        <button type="button" class="btn btn-ghost btn-sm" onclick="cardSelectClassToggle('${cs14Esc(cls)}',true)">Alle</button>
        <button type="button" class="btn btn-ghost btn-sm" onclick="cardSelectClassToggle('${cs14Esc(cls)}',false)">Ingen</button>
      </div>
      ${rows}
    </div>`;
  }).join('');

  document.getElementById('modal-card-select-body').innerHTML=
    `<div style="display:flex;gap:8px;flex-wrap:wrap;margin-bottom:.7rem;">
       <button type="button" class="btn btn-ghost btn-sm" onclick="cardSelectAll(true)">✓ Merk alle</button>
       <button type="button" class="btn btn-ghost btn-sm" onclick="cardSelectAll(false)">✕ Fjern alle</button>
       <div id="cs-count" style="flex:1;text-align:right;font-weight:800;color:var(--teal-dark);align-self:center;">${students.length} elever valgt</div>
     </div>
     <div style="max-height:380px;overflow-y:auto;">${groupsHTML}</div>`;
  document.getElementById('modal-card-select').classList.add('open');
}
function cardSelectAll(check){
  document.querySelectorAll('#modal-card-select-body .cs-cb').forEach(cb=>{ cb.checked=!!check; });
  cardSelectUpdateCount();
}
function cardSelectClassToggle(cls,check){
  document.querySelectorAll('#modal-card-select-body .cs-cb').forEach(cb=>{
    if(cb.dataset.class===cls) cb.checked=!!check;
  });
  cardSelectUpdateCount();
}
function cardSelectUpdateCount(){
  const n=document.querySelectorAll('#modal-card-select-body .cs-cb:checked').length;
  const el=document.getElementById('cs-count');
  if(el) el.textContent=n+' elever valgt';
  const btn=document.getElementById('card-select-print-btn');
  if(btn) btn.disabled=n===0;
}
function generateCardPDF() {
  const checked=new Set(Array.from(document.querySelectorAll('#modal-card-select-body .cs-cb:checked'))
    .map(cb=>cb.dataset.fbkey));
  const students=(window._students||[]).filter(s=>checked.has(s.fbKey));
  if (!students.length) {
    alert('Velg minst én elev å skrive ut kort for.');
    return;
  }
  // Innloggingsmodus: 'qrpin' = bare QR + PIN (PIN ikke trykket på kortet)
  // 'pin' (default) = PIN trykket på kortet
  const loginMode = (window._settings?.loginMode14 === 'qrpin') ? 'qrpin' : 'pin';
  const showPin = loginMode === 'pin';

  // På utskriften bruker vi en ren vektor-Myntland-mynt som portrett i stedet
  // for elevens monster-avatar (.webp). Grunnen: 8 monstre per A4 × mange ark
  // gjør PDF-en flere MB. Mynten er ren SVG (~1 KB per kort, ingen raster).
  // Eleven sin egen monster-avatar vises fortsatt i appen og i lærerportalen.
  const html = window.buildMyntlandBankCardsHTML(students, {
    showPin: showPin,
    // getAvatarSVG bevisst utelatt → coinPortraitSVG() brukes
    title: 'Myntland · Bankkort'
  });

  const win = window.open('', '_blank', 'width=900,height=900');
  win.document.write(html);
  win.document.close();
  // Auto-print fjernet — læreren ser banneret med utskriftsinstruksjoner
  // og trykker "Skriv ut nå"-knappen selv.
}

// ══════════════════════════════════════════════════════════
// LOGIN MODE TOGGLE (settings/loginMode14)
// ══════════════════════════════════════════════════════════
// 'pin'   = elever logger inn ved å taste 4-sifret PIN (PIN trykkes på kortet)
// 'qrpin' = elever scanner kortets QR-kode + bekrefter med PIN (PIN ikke på kortet)
async function setLoginMode14(mode) {
  if (mode !== 'pin' && mode !== 'qrpin') return;
  if (!window._db || !window._update || !window._ref) return;
  await window._update(window._ref(window._db, 'settings'), { loginMode14: mode });
  if (!window._settings) window._settings = {};
  window._settings.loginMode14 = mode;
  syncLoginModeToggle();
}

function syncLoginModeToggle() {
  const mode = (window._settings?.loginMode14 === 'qrpin') ? 'qrpin' : 'pin';
  const btnPin = document.getElementById('login-mode-pin');
  const btnQr  = document.getElementById('login-mode-qrpin');
  const hint   = document.getElementById('login-mode-hint');
  if (!btnPin || !btnQr) return;
  // Aktiv knapp får primær-stil
  btnPin.className = mode === 'pin'   ? 'btn btn-primary btn-sm' : 'btn btn-ghost btn-sm';
  btnQr.className  = mode === 'qrpin' ? 'btn btn-primary btn-sm' : 'btn btn-ghost btn-sm';
  btnPin.style.flex = '1'; btnPin.style.minWidth = '140px';
  btnQr.style.flex  = '1'; btnQr.style.minWidth  = '140px';
  if (hint) {
    hint.textContent = mode === 'qrpin'
      ? '📷 Eleven scanner kortet sitt og bekrefter med PIN. PIN-koden vises ikke på kortet.'
      : '🔢 Eleven taster bare PIN-koden for å logge inn. PIN-koden vises på kortet (kortene har likevel QR-kode for fleksibilitet).';
  }
}

// ══════════════════════════════════════════════════════════
// REAL VS PRETEND PAYMENTS TOGGLE (settings/realPayments14)
// ══════════════════════════════════════════════════════════
// true (default)  = elevens mynter trekkes fra konto ved kjøp i kassen
// false           = lekemodus: ingen mynter trekkes, kjøpet logges som "Lekekjøp"
async function setRealPayments14(real) {
  const val = !!real;
  if (!window._db || !window._update || !window._ref) return;
  await window._update(window._ref(window._db, 'settings'), { realPayments14: val });
  if (!window._settings) window._settings = {};
  window._settings.realPayments14 = val;
  syncRealPaymentsToggle();
}

function togglePaymentMode14() {
  const real = (window._settings?.realPayments14 !== false);
  setRealPayments14(!real);
}

function syncRealPaymentsToggle() {
  // Default = true (real)
  const real = (window._settings?.realPayments14 !== false);

  const box       = document.getElementById('payment-mode-status');
  const iconEl    = document.getElementById('payment-mode-icon');
  const labelEl   = document.getElementById('payment-mode-label');
  const titleEl   = document.getElementById('payment-mode-title');
  const descEl    = document.getElementById('payment-mode-desc');
  const switchBtn = document.getElementById('payment-mode-switch');
  const switchTxt = document.getElementById('payment-mode-switch-text');

  if (!box || !switchBtn) return;

  if (real) {
    // Ekte penger – grønn (teal)
    box.style.background    = 'var(--green-light)';
    box.style.borderColor   = 'var(--green)';
    box.style.color         = 'var(--green-dark)';
    iconEl.textContent      = '💰';
    labelEl.textContent     = 'Aktiv modus';
    titleEl.textContent     = 'Ekte mynter';
    descEl.textContent      = 'Mynter trekkes fra elevens konto når kjøp bekreftes. Transaksjonen vises i historikken.';
    switchTxt.textContent   = '🎮 Bytt til lekemodus';
  } else {
    // Lekemodus – lilla
    box.style.background    = 'var(--purple-light)';
    box.style.borderColor   = 'var(--purple)';
    box.style.color         = 'var(--purple)';
    iconEl.textContent      = '🎮';
    labelEl.textContent     = 'Aktiv modus';
    titleEl.textContent     = 'Lekemodus';
    descEl.textContent      = 'Kassen viser «Betalt!», men ingen mynter trekkes fra elevens konto. Kjøpet logges som lekekjøp.';
    switchTxt.textContent   = '💰 Bytt til ekte mynter';
  }
}

