// MYNTJAKTEN-INNSTILLINGER (settings/myntjakten14)
// ══════════════════════════════════════════════════════════
// { enabled: bool, dailyMax: int (0 = ingen grense) }
// Brukes av myntjakten.html for å avgjøre om en elev kan tjene mynter.
function syncMyntjakten14Form() {
  const mj = (window._settings && window._settings.myntjakten14) || {};
  const enabledEl = document.getElementById('myntjakten14-enabled');
  const maxEl     = document.getElementById('myntjakten14-daily-max');
  if (enabledEl) enabledEl.checked = mj.enabled !== false;
  if (maxEl)     maxEl.value       = (mj.dailyMax != null) ? mj.dailyMax : 0;
  // Aktive nivå — mangler feltet (eldre datasett) → alle nivå på
  const al = mj.activeLevels;
  for (let i = 1; i <= 6; i++) {
    const cb = document.getElementById('myntjakten14-level-' + i);
    if (cb) cb.checked = !al || al[i] !== false;
  }
  // Statistikk oppdateres samtidig
  renderMyntjaktenStats14();
}

// Lokal "i dag"-nøkkel — må matche logikken i myntjakten.html
function _myntjaktenTodayKey14() {
  const d = new Date();
  return d.getFullYear() + '-' + String(d.getMonth()+1).padStart(2,'0') + '-' + String(d.getDate()).padStart(2,'0');
}

function renderMyntjaktenStats14() {
  const summaryEl = document.getElementById('myntjakten14-stats-summary');
  const topEl     = document.getElementById('myntjakten14-stats-top');
  if (!summaryEl || !topEl) return;

  const students = window._students || [];
  const today = _myntjaktenTodayKey14();

  const active = students
    .map(s => {
      const t = s.myntjaktenToday;
      if (!t || t.date !== today) return null;
      const earned = parseInt(t.earned) || 0;
      if (earned <= 0) return null;
      return { name: s.name || s.id, earned };
    })
    .filter(Boolean)
    .sort((a, b) => b.earned - a.earned);

  if (active.length === 0) {
    summaryEl.textContent = 'Ingen elever har tjent mynter via spillene i dag ennå.';
    topEl.textContent = '';
    return;
  }

  const total = active.reduce((sum, a) => sum + a.earned, 0);
  summaryEl.innerHTML = '👥 <strong>' + active.length + '</strong> elev' +
    (active.length === 1 ? '' : 'er') + ' har tjent totalt <strong>🪙 ' + total + '</strong> i dag.';

  const top = active.slice(0, 5);
  topEl.innerHTML = '🏆 ' + top.map(a => a.name + ' (🪙 ' + a.earned + ')').join(' · ');
}

async function saveMyntjakten14Settings() {
  const alertEl = document.getElementById('myntjakten14-alert');
  const enabled = !!document.getElementById('myntjakten14-enabled').checked;
  const dailyMax = parseInt(document.getElementById('myntjakten14-daily-max').value);

  if (isNaN(dailyMax) || dailyMax < 0 || dailyMax > 9999) {
    alertEl.innerHTML = '<div class="alert alert-error">⚠️ Dagstak må være et tall mellom 0 og 9999 (0 = ingen grense).</div>';
    return;
  }

  // Aktive nivå — minst ett må være på
  const activeLevels = {};
  let levelCount = 0;
  for (let i = 1; i <= 6; i++) {
    const on = !!document.getElementById('myntjakten14-level-' + i).checked;
    activeLevels[i] = on;
    if (on) levelCount++;
  }
  if (levelCount === 0) {
    alertEl.innerHTML = '<div class="alert alert-error">⚠️ Minst ett nivå må være aktivt i Myntjakten.</div>';
    return;
  }

  if (!window._db || !window._update || !window._ref) {
    alertEl.innerHTML = '<div class="alert alert-error">⚠️ Database ikke klar. Prøv igjen.</div>';
    return;
  }

  try {
    await window._update(window._ref(window._db, 'settings'), {
      myntjakten14: { enabled, dailyMax, activeLevels, updated: Date.now() }
    });
    if (!window._settings) window._settings = {};
    window._settings.myntjakten14 = { enabled, dailyMax, activeLevels };

    const levelNote = levelCount < 6 ? ` ${levelCount} av 6 nivå er aktive.` : '';
    const status = (enabled
      ? (dailyMax > 0
          ? `✅ Lagret. Elevene kan tjene opp til 🪙 ${dailyMax} per dag via spillene.`
          : '✅ Lagret. Ingen dagstak — elevene kan tjene fritt.')
      : '✅ Lagret. Opptjening via spillene er slått av.') + levelNote;
    alertEl.innerHTML = '<div class="alert alert-success">' + status + '</div>';
    setTimeout(() => alertEl.innerHTML = '', 3500);
  } catch(e) {
    alertEl.innerHTML = '<div class="alert alert-error">⚠️ Lagring feilet: ' + e.message + '</div>';
  }
}

