// PDF PRINT HELPER
// ══════════════════════════════════════════════════════════
// Opens a clean popup with only the PDF content and triggers print.
// This avoids printing the whole portal UI.
function printWindow(htmlContent, pageSize) {
  const size = pageSize || 'A4 portrait';
  const win = window.open('', '_blank', 'width=900,height=700');
  win.document.write(`<!DOCTYPE html><html><head>
    <meta charset="UTF-8">
    <link href="https://fonts.googleapis.com/css2?family=Fredoka+One&family=Nunito:wght@400;700;800&display=swap" rel="stylesheet">
    <style>
      * { box-sizing: border-box; margin: 0; padding: 0; }
      body { font-family: 'Nunito', sans-serif; background: white; }
      @media print { @page { size: ${size}; margin: 8mm; } }
    </style>
  </head><body>${htmlContent}</body></html>`);
  win.document.close();
  // Wait for fonts to load before printing
  win.onload = () => { win.focus(); win.print(); };
  // Fallback if onload doesn't fire (some browsers)
  setTimeout(() => { try { win.focus(); win.print(); } catch(e){} }, 800);
}

