// SPAREMÅL – classGoals14 (per klasse)
// ════════════════════════════════════════════════════════════
window._classGoals = window._classGoals || [];

// Hjelper: hvilken klasse jobber læreren med på sparemål-siden?
function getActiveGoalClass() {
  const t = window._currentTeacher;
  // 1) Lærer låst til egen klasse
  if (t?.class) return t.class;
  // 2) Klassen som vises i elevlista akkurat nå
  if (typeof classFilter !== 'undefined' && classFilter) return classFilter;
  // 3) Sikkerhetsnett: finnes nøyaktig én klasse blant elevene, bruk den
  const klasser = [...new Set((window._students || []).map(s => s.class))].filter(Boolean);
  if (klasser.length === 1) return klasser[0];
  return '';
}

async function distributeToGoals14(amount) {
  // Beholdt for bakoverkompatibilitet, men ikke lenger i bruk – skatt går nå
  // direkte til elevens valgte sparemål i elevens egen klasse.
  if (!amount || !window._classGoals?.length) return;
  const active = window._classGoals.filter(g => !g.completed);
  if (!active.length) return;
  const perGoal = Math.floor(amount / active.length);
  if (perGoal <= 0) return;
  const upd = {};
  active.forEach(g => {
    const ns = (g.saved || 0) + perGoal;
    upd['classGoals14/' + g.fbKey + '/saved'] = ns;
    if (ns >= g.target) upd['classGoals14/' + g.fbKey + '/completed'] = true;
  });
  await window._update(fbRef('/'), upd);
}

async function createClassGoal() {
  if (!ready()) return;
  const cls = getActiveGoalClass();
  if (!cls) {
    document.getElementById('goal-alert').innerHTML = '<div class="alert alert-error">⚠️ Velg en klasse først.</div>';
    return;
  }
  const active = (window._classGoals || []).filter(g => !g.completed && g.class === cls);
  if (active.length >= 3) {
    document.getElementById('goal-alert').innerHTML = '<div class="alert alert-error">⚠️ Maks 3 aktive sparemål samtidig i ' + cls + '.</div>';
    return;
  }
  const emoji  = document.getElementById('goal-emoji').value.trim() || '🏦';
  const name   = document.getElementById('goal-name').value.trim();
  const target = parseInt(document.getElementById('goal-target').value) || 1000;
  const desc   = document.getElementById('goal-desc').value.trim();
  if (!name) {
    document.getElementById('goal-alert').innerHTML = '<div class="alert alert-error">⚠️ Skriv inn et navn på sparemålet.</div>';
    return;
  }
  await window._set(window._push(fbRef('classGoals14')), {
    emoji, name, target, desc, saved: 0, completed: false, created: Date.now(), class: cls
  });
  ['goal-emoji','goal-name','goal-desc'].forEach(id => document.getElementById(id).value = '');
  document.getElementById('goal-target').value = '1000';
  document.getElementById('goal-alert').innerHTML = '<div class="alert alert-success">✅ «' + name + '» opprettet for ' + cls + '!</div>';
  setTimeout(() => document.getElementById('goal-alert').innerHTML = '', 3000);
}

async function deleteClassGoal(fbKey) {
  if (!confirm('Slett sparemål? Sparte mynter forsvinner.')) return;
  await window._remove(fbRef('classGoals14/' + fbKey));
}

function renderClassGoalsPage() {
  const el = document.getElementById('class-goals-container');
  if (!el) return;
  const t = window._currentTeacher;
  const isAdmin = t?.role === 'admin';
  const cls = getActiveGoalClass();

  // Klasse-velger fjernet – sparemål gjelder alltid lærerens egen klasse
  const filterCard = document.getElementById('goal-class-filter-card');
  if (filterCard) filterCard.style.display = 'none';

  // Oppdater "Nytt sparemål"-kortet med klassenavn
  const newCardLabel = document.getElementById('new-goal-class-label');
  if (newCardLabel) newCardLabel.textContent = cls ? '· ' + cls : '';

  // Subtitle
  const sub = document.getElementById('sparemaal-subtitle');
  if (sub) {
    sub.textContent = cls
      ? 'Maks 3 aktive sparemål for ' + cls + '. Skatt fra elevene i ' + cls + ' går til disse sparemålene.'
      : 'Maks 3 aktive sparemål per klasse. Skatt fra elevene går til sparemålene i deres egen klasse.';
  }

  // Filtrer sparemål etter aktiv klasse
  const allGoals = window._classGoals || [];
  const goals = allGoals.filter(g => g.class === cls);
  const legacy = allGoals.filter(g => !g.class); // gamle sparemål uten klasse
  const active = goals.filter(g => !g.completed);
  const done   = goals.filter(g =>  g.completed);
  const newCard = document.getElementById('new-goal-card');
  if (newCard) newCard.style.display = active.length >= 3 ? 'none' : 'block';

  // Legacy-varsel kun for admin
  let legacyHTML = '';
  if (legacy.length) {
    legacyHTML = `<div class="card" style="background:#FEF3C7;border:2px solid var(--amber);">
      <div style="font-weight:800;color:#854F0B;margin-bottom:.5rem;">⚠️ ${legacy.length} sparemål uten klasse</div>
      <div style="font-size:.85rem;color:#92400E;margin-bottom:.75rem;">Disse ble opprettet før klasse-funksjonen og vises ikke til elevene. Slett dem og opprett nye for hver klasse:</div>
      ${legacy.map(g => `<div style="display:flex;align-items:center;gap:8px;padding:.5rem;background:white;border-radius:8px;margin-bottom:.4rem;">
        <span style="font-size:1.2rem;">${g.emoji||'🏦'}</span>
        <span style="flex:1;font-weight:700;">${g.name}</span>
        <span style="font-size:.8rem;color:var(--muted);">🪙 ${g.saved||0}/${g.target}</span>
        <button onclick="deleteClassGoal('${g.fbKey}')" style="background:none;border:none;cursor:pointer;color:var(--coral);font-size:1.1rem;">🗑️</button>
      </div>`).join('')}
    </div>`;
  }

  if (!goals.length) {
    el.innerHTML = legacyHTML + '<div class="card" style="text-align:center;color:var(--muted);padding:1.5rem;">Ingen sparemål for ' + (cls || 'denne klassen') + ' ennå. Opprett ett under!</div>';
    return;
  }
  el.innerHTML = legacyHTML + [...active, ...done].map(g => {
    const pct = Math.min(100, Math.round((g.saved||0) / g.target * 100));
    return `<div class="card">
      <div style="display:flex;align-items:center;gap:12px;margin-bottom:.75rem;">
        <div style="font-size:1.8rem;">${g.emoji||'🏦'}</div>
        <div style="flex:1;"><div style="font-weight:800;font-size:1.05rem;">${g.name}${g.completed?' ✅':''}</div><div style="font-size:.8rem;color:var(--muted);">Mål: 🪙 ${g.target}${g.desc?' · '+g.desc:''}${g.class?' · '+g.class:''}</div></div>
        <button onclick="deleteClassGoal('${g.fbKey}')" style="background:none;border:none;cursor:pointer;color:var(--coral);font-size:1.1rem;">🗑️</button>
      </div>
      <div style="height:12px;background:var(--bg);border-radius:20px;overflow:hidden;margin-bottom:.5rem;border:1px solid var(--border);">
        <div style="height:100%;background:${g.completed?'#16a34a':'var(--green)'};border-radius:20px;width:${pct}%;transition:width .4s;"></div>
      </div>
      <div style="display:flex;justify-content:space-between;font-size:.82rem;font-weight:700;color:var(--muted);">
        <span>🪙 ${g.saved||0} spart</span><span>${pct}%</span><span>🪙 ${Math.max(0,g.target-(g.saved||0))} igjen</span>
      </div>
    </div>`;
  }).join('');
}

