async function addHendelse() {
  if (!ready()) return;
  const emoji  = document.getElementById('hend-emoji').value.trim() || '🎲';
  const desc   = document.getElementById('hend-desc').value.trim();
  const type   = document.getElementById('hend-type').value;
  const amount = parseInt(document.getElementById('hend-amount').value) || 0;
  const alertEl = document.getElementById('hend-alert');
  if (!desc) { alertEl.innerHTML = '<div class="alert alert-error">⚠️ Skriv inn en beskrivelse.</div>'; return; }
  if (amount < 1 || amount > 999) { alertEl.innerHTML = '<div class="alert alert-error">⚠️ Beløp må være mellom 1 og 999.</div>'; return; }
  await window._set(window._push(fbRef('hendelser14')), { emoji, desc, type, amount, created: Date.now() });
  document.getElementById('hend-emoji').value  = '';
  document.getElementById('hend-desc').value   = '';
  document.getElementById('hend-amount').value = '';
  alertEl.innerHTML = '<div class="alert alert-success">✅ Hendelse lagt til!</div>';
  setTimeout(() => alertEl.innerHTML = '', 2500);
}

async function deleteHendelse(fbKey) {
  if (!confirm('Slett denne hendelsen?')) return;
  await window._remove(fbRef('hendelser14/' + fbKey));
}

async function clearAllHendelser() {
  if (!confirm('Slett ALLE hendelser? Dette kan ikke angres.')) return;
  await window._remove(fbRef('hendelser14'));
}

async function seedDefaultHendelser() {
  if (!ready()) return;
  const hend = window._hendelser || [];
  if (hend.length > 0) {
    if (!confirm('Du har allerede ' + hend.length + ' hendelser. Legg til 30 standard i tillegg?')) return;
  }
  const alertEl = document.getElementById('hend-alert');
  if (alertEl) alertEl.innerHTML = '<div class="alert alert-info">⏳ Laster inn 30 hendelser…</div>';
  try {
    await Promise.all(DEFAULT_HENDELSER_14.map(function(h) {
      return window._set(window._push(fbRef('hendelser14')), Object.assign({}, h, { created: Date.now() }));
    }));
    if (alertEl) {
      alertEl.innerHTML = '<div class="alert alert-success">✅ 30 standard hendelser lagt til!</div>';
      setTimeout(function() { alertEl.innerHTML = ''; }, 3000);
    }
  } catch(err) {
    console.error('seedDefaultHendelser feilet:', err);
    if (alertEl) alertEl.innerHTML = '<div class="alert alert-error">❌ Feil: ' + err.message + '</div>';
  }
}

function renderHendelser() {
  const list = document.getElementById('hendelser-list');
  if (!list) return;
  const filter = document.getElementById('hend-filter')?.value || 'all';
  const all = window._hendelser || [];
  const income  = all.filter(h => h.type === 'income');
  const expense = all.filter(h => h.type === 'expense');
  const ct = document.getElementById('hend-count-total');
  const ci = document.getElementById('hend-count-income');
  const ce = document.getElementById('hend-count-expense');
  if (ct) ct.textContent = all.length;
  if (ci) ci.textContent = income.length;
  if (ce) ce.textContent = expense.length;
  const filtered = filter === 'all' ? all : all.filter(h => h.type === filter);
  if (!filtered.length) {
    list.innerHTML = '<div style="color:var(--muted);font-size:.9rem;padding:1rem;">Ingen hendelser å vise. Trykk «Last inn 30 standard» for å komme i gang.</div>';
    return;
  }
  list.innerHTML = filtered.map(h => {
    const isIncome = h.type === 'income';
    const bg     = isIncome ? '#dcfce7' : '#fee2e2';
    const color  = isIncome ? '#15803d' : '#dc2626';
    const border = isIncome ? '#86efac' : '#fca5a5';
    const sign   = isIncome ? '+' : '-';
    return `<div style="background:${bg};border:1.5px solid ${border};border-radius:12px;padding:.85rem 1rem;display:flex;flex-direction:column;gap:.4rem;position:relative;">
      <div style="display:flex;align-items:center;gap:.5rem;">
        <span style="font-size:1.6rem;">${h.emoji||'🎲'}</span>
        <div style="flex:1;">
          <div style="font-weight:800;font-size:.88rem;color:var(--green-dark);line-height:1.2;">${h.desc}</div>
          <div style="font-size:.82rem;font-weight:900;color:${color};margin-top:2px;">${sign}🪙${h.amount}</div>
        </div>
        <div style="display:flex;gap:4px;">
          <button class="btn btn-ghost btn-sm" onclick="showHendelseQR14('${h.fbKey}')" title="Vis QR">⬛</button>
          <button class="btn btn-ghost btn-sm" onclick="deleteHendelse('${h.fbKey}')" title="Slett" style="color:var(--coral);">🗑️</button>
        </div>
      </div>
    </div>`;
  }).join('');
}

function showHendelseQR14(fbKey) {
  const h = (window._hendelser || []).find(x => x.fbKey === fbKey);
  if (!h) return;
  const payload = JSON.stringify({ type: 'event', subtype: h.type, amount: h.amount, desc: h.desc });
  const modal = document.getElementById('modal-hend-qr');
  const box   = document.getElementById('modal-hend-qr-box');
  const title = document.getElementById('modal-hend-qr-title');
  const desc  = document.getElementById('modal-hend-qr-desc');
  const isIncome = h.type === 'income';
  const sign = isIncome ? '+' : '-';
  title.textContent = (h.emoji||'🎲') + ' ' + h.desc;
  desc.textContent  = (isIncome ? '💰 Inntekt' : '💸 Utgift') + ': ' + sign + '🪙' + h.amount;
  box.innerHTML     = '<div style="width:250px;height:250px;display:flex;align-items:center;justify-content:center;color:var(--muted);font-size:.85rem;">Genererer QR…</div>';
  modal.classList.add('open');
  requestAnimationFrame(() => requestAnimationFrame(() => {
    box.innerHTML = '';
    try {
      new QRCode(box, { text: payload, width: 250, height: 250, correctLevel: QRCode.CorrectLevel.M });
    } catch(e) {
      box.innerHTML = '<p style="color:var(--coral);font-size:.82rem;">Kunne ikke generere QR</p>';
    }
    setTimeout(() => {
      const canvas = box.querySelector('canvas');
      if (canvas) document.getElementById('hend-qr-print-btn')._qrDataUrl = canvas.toDataURL('image/png');
    }, 200);
    document.getElementById('hend-qr-print-btn')._hendelse = h;
  }));
}

function printHendelseQRCard() {
  const btn = document.getElementById('hend-qr-print-btn');
  const h   = btn._hendelse;
  if (!h) { alert('Velg en hendelse først.'); return; }
  const qrSVG = window.qrToSVG({ type:'event', subtype:h.type, amount:h.amount, desc:h.desc }, 25, 'L');
  printHendelserCards14([{ ...h, qrSVG: qrSVG }]);
}

function printHendelser() {
  const all = window._hendelser || [];
  if (!all.length) { alert('Ingen hendelser å skrive ut.'); return; }
  const cards = all.map(h => ({
    ...h,
    qrSVG: window.qrToSVG({ type:'event', subtype:h.type, amount:h.amount, desc:h.desc }, 25, 'L')
  }));
  printHendelserCards14(cards);
}

function printHendelserCards14(cards) {
  const win = window.open('', '_blank', 'width=900,height=700');
  const cardHTML = (c) => {
    const isIncome = c.type === 'income';
    const cls      = isIncome ? 'income' : 'expense';
    const sign     = isIncome ? '+' : '−';
    const label    = isIncome ? 'INNTEKT' : 'UTGIFT';
    const qrMarkup = c.qrSVG
      ? c.qrSVG
      : `<img src="${c.qrUrl || c._dataUrl || ''}" width="130" height="130" alt="QR">`;
    return `<div class="hcard ${cls}">
      <div class="pill">${label}</div>
      <div class="emoji">${c.emoji||'🎲'}</div>
      <div class="desc">${c.desc}</div>
      <div class="amount"><span class="sign">${sign}</span><span class="coin-icon">🪙</span><span class="num">${c.amount}</span></div>
      <div class="qr-block">
        <div class="qr-wrap">${qrMarkup}</div>
        <div class="scan-hint">Scan for å registrere</div>
      </div>
      <div class="card-foot"><span class="foot-coin">🪙</span><span class="foot-stamp">MYNTLAND · HENDELSER</span></div>
    </div>`;
  };
  let pagesHTML = '';
  // Baksiden er ensfarget og nøytral — bevisst UTEN income/expense-klasse.
  // Da avslører den ikke om kortet er inntekt eller utgift (viktig hvis
  // hendelsene skal trekkes fysisk), og fargekanten synes ikke ved
  // små forskyvninger i tosidig utskrift.
  const backHTML = () => `<div class="hcard hback">
    <div class="back-coin">🪙</div>
    <div class="back-logo">MYNTLAND</div>
    <div class="back-sub">Hendelser</div>
  </div>`;
  // For long-edge flip: speilvend hver rad så baksiden lander rett under forsiden
  const backsForFronts = (group) => {
    const out = new Array(group.length);
    for (let i = 0; i < group.length; i += 2) {
      const a = group[i], b = group[i+1];
      out[i]   = b != null ? backHTML() : '<div class="hcard empty"></div>';
      out[i+1] = a != null ? backHTML() : '<div class="hcard empty"></div>';
    }
    return out.join('');
  };
  for (let i = 0; i < cards.length; i += 4) {
    const group = cards.slice(i, i+4);
    while (group.length < 4) group.push(null);
    pagesHTML += `<div class="page-print">
      ${group.map(c => c ? cardHTML(c) : '<div class="hcard empty"></div>').join('')}
    </div>`;
    pagesHTML += `<div class="page-print back-page">
      ${backsForFronts(group)}
    </div>`;
  }
  const _bhend = window.buildPdfDownloadBanner('', { twoSided: true });
  win.document.write(`<!DOCTYPE html><html lang="nb"><head><meta charset="UTF-8"><style>img.myntico{height:1em;width:auto;vertical-align:-0.16em;margin:0 .04em}</style><script>(function(){var U=(window.opener&&window.opener.__MYNTCOIN__)||"https://myntland.no/mynt.webp";var E="🪙";function C(n){if(n.nodeType===3){var v=n.nodeValue;if(!v||v.indexOf(E)<0)return;var p=n.parentNode;if(!p)return;var t=p.nodeName;if(t==="SCRIPT"||t==="STYLE"||t==="TEXTAREA")return;var a=v.split(E),f=document.createDocumentFragment();for(var i=0;i<a.length;i++){if(a[i])f.appendChild(document.createTextNode(a[i]));if(i<a.length-1){var m=document.createElement("img");m.className="myntico";m.src=U;m.alt="mynt";f.appendChild(m);}}p.replaceChild(f,n);}else if(n.nodeType===1){var k=[].slice.call(n.childNodes);for(var j=0;j<k.length;j++)C(k[j]);}}function R(){try{C(document.body);}catch(e){}}if(document.readyState==="loading"){document.addEventListener("DOMContentLoaded",R);}else{R();}})();</script>
  <link rel="preconnect" href="https://fonts.googleapis.com">
  <link rel="preconnect" href="https://fonts.gstatic.com" crossorigin>
  <link href="https://fonts.googleapis.com/css2?family=Fraunces:ital,wght@0,700;0,900;1,700;1,900&family=Nunito:wght@400;700;800;900&family=Bowlby+One&display=swap" rel="stylesheet">
  <style>
    :root{
      --blekk:#2A1F3D;--blekk-myk:#4A3D5C;
      --gront:#1D9E75;--gront-dyp:#085041;--gront-mykt:#E5F5EE;
      --rod:#C13D2F;--rod-dyp:#7A2218;--rod-mykt:#F9E8E5;
    }
    *{box-sizing:border-box;margin:0;padding:0}
    html,body{font-family:'Nunito',sans-serif;background:white;color:var(--blekk);-webkit-print-color-adjust:exact;print-color-adjust:exact}
    @page{size:A4 portrait;margin:0}

    /* 2x2 grid: 4 kort per A4. Printbart omr. 194×281mm; arket gjoeres litt
       lavere (275mm) saa iPad/Safari ikke runder over til blank ekstra side. */
    .page-print{width:210mm;height:275mm;max-height:275mm;margin:0 auto;overflow:hidden;display:grid;grid-template-columns:1fr 1fr;grid-template-rows:1fr 1fr;page-break-after:always;break-after:page;position:relative}
    .page-print:last-child{page-break-after:avoid}

    /* Kortet: fyller hele sin firkant. Tonet bakgrunn per type. */
    .hcard{padding:7mm 8mm 5mm;display:flex;flex-direction:column;align-items:center;justify-content:flex-start;text-align:center;position:relative;page-break-inside:avoid;height:100%}
    .hcard.empty{visibility:hidden}
    .hcard.income{background:var(--gront-mykt)}
    .hcard.expense{background:var(--rod-mykt)}

    /* Klippelinjer mellom kort — KUN på forsiden (ikke .back-page) */
    .page-print:not(.back-page) > .hcard:nth-child(1),
    .page-print:not(.back-page) > .hcard:nth-child(2){border-bottom:1px dashed var(--blekk-myk)}
    .page-print:not(.back-page) > .hcard:nth-child(1),
    .page-print:not(.back-page) > .hcard:nth-child(3){border-right:1px dashed var(--blekk-myk)}

    /* Pill — størst luft her, så den "puster" øverst */
    .pill{font-family:'Nunito',sans-serif;font-weight:800;font-size:10pt;letter-spacing:.24em;color:white;padding:2.2mm 7mm;border-radius:999px;margin-bottom:6mm}
    .income .pill{background:var(--gront)}
    .expense .pill{background:var(--rod)}

    /* Emoji: dominerende */
    .emoji{font-size:26mm;line-height:1;margin-bottom:2mm}

    /* Tittel: midtstilt, max 2 linjer */
    .desc{font-family:'Nunito',sans-serif;font-weight:900;font-size:12pt;color:var(--blekk);line-height:1.2;max-width:80mm;margin-bottom:2mm}

    /* Beløp — tett mot QR-en under */
    .amount{display:flex;align-items:center;justify-content:center;gap:2mm;margin-bottom:0;line-height:1}
    .amount .sign{font-family:'Nunito',sans-serif;font-weight:900;font-size:23pt;line-height:1}
    .amount .coin-icon{font-size:18pt;line-height:1}
    .amount .num{font-family:'Nunito',sans-serif;font-weight:900;font-size:23pt;line-height:1}
    .income .amount .sign,.income .amount .num{color:var(--gront)}
    .expense .amount .sign,.expense .amount .num{color:var(--rod)}

    /* QR-blokk: kommer rett etter beløp, ikke sentrert i tomrom */
    .qr-block{display:flex;flex-direction:column;align-items:center;gap:1.5mm;margin-top:3mm;margin-bottom:1mm}
    .qr-wrap{padding:2mm;background:white;border:1px solid rgba(42,31,61,.1);border-radius:2mm}
    .qr-wrap img,.qr-wrap svg{display:block;width:34mm;height:34mm}

    /* Hint */
    .scan-hint{font-family:'Nunito',sans-serif;font-size:8pt;color:var(--blekk-myk);font-weight:600;letter-spacing:.04em}

    /* Footer: Myntland-stempel i bunn av kortet (forsiden) */
    .card-foot{display:flex;align-items:center;justify-content:center;gap:2mm;padding-top:3mm;margin-top:auto;border-top:1px dashed var(--blekk-myk);width:78mm;max-width:88%}
    .card-foot .foot-coin{font-size:9pt;line-height:1}
    .card-foot .foot-stamp{font-family:'Bowlby One',sans-serif;font-size:8pt;color:var(--blekk);letter-spacing:.14em}
    .income .card-foot{border-top-color:var(--gront-dyp)}
    .expense .card-foot{border-top-color:var(--rod-dyp)}

    /* ── Bakside ── ensfarget og nøytral, uten klippelinjer.
       Nøytral farge (ikke grønn/rød) slik at baksiden ikke avslører
       om kortet er inntekt eller utgift ved fysisk trekning. */
    .hcard.hback{background:#FFF6E0}
    .hback{display:flex;flex-direction:column;align-items:center;justify-content:center;padding:9mm}
    .back-coin{font-size:30mm;line-height:1;margin-bottom:3mm}
    .back-logo{font-family:'Bowlby One',sans-serif;font-size:18pt;color:var(--blekk);letter-spacing:.02em;line-height:1}
    .back-sub{font-family:'Fraunces',serif;font-style:italic;font-weight:900;font-size:11pt;color:var(--blekk-myk);margin-top:2mm;letter-spacing:.08em}

    ${_bhend.bannerCSS}
  </style>
  </head><body>${_bhend.bannerHTML}${pagesHTML}</body></html>`);
  win.document.close();
}
// ════════════════════════════════════════════════════════════
// MERKER (1–4)
// ════════════════════════════════════════════════════════════

const DEFAULT_BADGE_PARAMS_14 = {
  renterBronse: 50,  renterSolv: 150, renterGull: 300,
  quizBronse:   25,  quizSolv:    50, quizGull:    75,
  bonusBronse:  100, bonusSolv:   500, bonusGull:  1000
};

function loadBadgeParamsToForm() {
  const bp = window._settings?.badgeParams14 || DEFAULT_BADGE_PARAMS_14;
  const fields = ['renterBronse','renterSolv','renterGull','quizBronse','quizSolv','quizGull','bonusBronse','bonusSolv','bonusGull'];
  fields.forEach(f => {
    const el = document.getElementById('bp14-' + f);
    if (el) el.value = bp[f] !== undefined ? bp[f] : DEFAULT_BADGE_PARAMS_14[f];
  });
}

async function saveBadgeParams14() {
  const alertEl = document.getElementById('bp14-save-alert');
  const fields = ['renterBronse','renterSolv','renterGull','quizBronse','quizSolv','quizGull','bonusBronse','bonusSolv','bonusGull'];
  const bp = {};
  for (const f of fields) {
    const v = parseInt(document.getElementById('bp14-' + f)?.value);
    if (isNaN(v) || v < 0) {
      alertEl.textContent = '⚠️ Alle felter må være positive tall';
      alertEl.style.color = 'var(--coral)';
      return;
    }
    bp[f] = v;
  }
  try {
    await window._update(fbRef('settings'), { badgeParams14: bp });
    if (!window._settings) window._settings = {};
    window._settings.badgeParams14 = bp;
    alertEl.textContent = '✅ Lagret!';
    alertEl.style.color = 'var(--green-dark)';
    setTimeout(() => alertEl.textContent = '', 2500);
    renderMerkerPage();
  } catch(e) {
    alertEl.textContent = '⚠️ Feilet: ' + e.message;
    alertEl.style.color = 'var(--coral)';
  }
}

async function confirmBadgeReset14() {
  const cls = document.getElementById('badge14-reset-class').value;
  const alertEl = document.getElementById('badge14-reset-alert');
  const target = cls ? cls : 'alle elever';
  if (!confirm(`⚠️ Vil du virkelig slette ALLE merker og nullstille fremgang for ${target}? Dette kan ikke angres!`)) return;

  try {
    const students = window._students.filter(s => !cls || s.class === cls);
    const updates = {};
    for (const s of students) {
      updates['students14/' + s.fbKey + '/badges'] = null;
      updates['students14/' + s.fbKey + '/badgeRenterEarned'] = 0;
      updates['students14/' + s.fbKey + '/quizCorrectTotal'] = 0;
    }
    await window._update(fbRef('/'), updates);
    alertEl.innerHTML = `<div class="alert alert-success">✅ Merker nullstilt for ${students.length} elever!</div>`;
    setTimeout(() => alertEl.innerHTML = '', 3500);
    renderMerkerPage();
  } catch(e) {
    alertEl.innerHTML = `<div class="alert alert-error">⚠️ Feilet: ${e.message}</div>`;
  }
}

function badgeLevelBadge14(earned, level) {
  const labels = { bronse: '🥉', sølv: '🥈', gull: '🥇' };
  if (earned) return `<span title="Oppnådd ${level}" style="font-size:1.1rem;">${labels[level]}</span>`;
  return `<span title="Ikke oppnådd ${level}" style="opacity:.25;font-size:1.1rem;">${labels[level]}</span>`;
}

function renderMerkerPage() {
  loadBadgeParamsToForm();
  const tbody = document.getElementById('merker14-table-body'); if (!tbody) return;
  const cls = document.getElementById('merker14-class-filter')?.value || '';
  const bp = window._settings?.badgeParams14 || DEFAULT_BADGE_PARAMS_14;
  const students = (window._students || []).filter(s => !cls || s.class === cls);

  if (!students.length) {
    tbody.innerHTML = '<tr><td colspan="6" style="text-align:center;color:var(--muted);padding:2rem;">Ingen elever</td></tr>';
    return;
  }

  // Sort by lastname, firstname
  const sorted = [...students].sort((a,b) => {
    return (a.lastname||'').localeCompare(b.lastname||'') || (a.firstname||'').localeCompare(b.firstname||'');
  });

  tbody.innerHTML = sorted.map(s => {
    const badges = s.badges || {};
    const renter = s.badgeRenterEarned || 0;
    const quiz   = s.quizCorrectTotal  || 0;

    const renterLevels = badgeLevelBadge14(!!badges.renter_bronse,'bronse')
                       + badgeLevelBadge14(!!badges.renter_sølv,'sølv')
                       + badgeLevelBadge14(!!badges.renter_gull,'gull');
    const quizLevels   = badgeLevelBadge14(!!badges.quiz_bronse,'bronse')
                       + badgeLevelBadge14(!!badges.quiz_sølv,'sølv')
                       + badgeLevelBadge14(!!badges.quiz_gull,'gull');

    const renterPct = Math.min(100, Math.round(renter / bp.renterGull * 100));
    const quizPct   = Math.min(100, Math.round(quiz   / bp.quizGull   * 100));

    const miniBar = (pct, color) => `<div style="height:4px;background:#e5e7eb;border-radius:4px;margin-top:3px;overflow:hidden;width:80px;display:inline-block;"><div style="height:100%;width:${pct}%;background:${color};border-radius:4px;"></div></div>`;

    return `<tr>
      <td data-label="Elev"><div style="font-weight:800;font-size:.88rem;">${s.firstname||''} ${s.lastname||''}</div></td>
      <td data-label="Renter"><div style="font-weight:800;">🪙 ${renter}</div>${miniBar(renterPct, '#16a34a')}</td>
      <td data-label="Nivå">${renterLevels}</td>
      <td data-label="Quiz"><div style="font-weight:800;">${quiz}</div>${miniBar(quizPct, '#7c3aed')}</td>
      <td data-label="Nivå">${quizLevels}</td>
    </tr>`;
  }).join('');
}

